CREATE SCHEMA IF NOT EXISTS cad;

CREATE OR REPLACE FUNCTION cad._abbrev(p_label text, p_role text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_label LIKE 'Poteau %' THEN replace(substr(p_label, 8), ' ', '')
    WHEN p_label LIKE 'Traverse %' THEN 't' || replace(substr(p_label, 10), ' ', '')
    WHEN p_label LIKE 'Lisse bas %' THEN 'b' || replace(substr(p_label, 11), ' ', '')
    WHEN p_label LIKE 'Lisse mid %' THEN 'm' || replace(substr(p_label, 11), ' ', '')
    WHEN p_label LIKE 'Lisse haut %' THEN 'h' || replace(substr(p_label, 12), ' ', '')
    WHEN p_label LIKE 'Chevron AV-%' THEN 'V' || replace(substr(p_label, 12), '-', '')
    WHEN p_label LIKE 'Chevron AR-%' THEN 'R' || replace(substr(p_label, 12), '-', '')
    WHEN p_label LIKE 'Chevron %' THEN 'C' || replace(substr(p_label, 9), ' ', '')
    WHEN p_label = 'Faitiere' THEN 'F'
    WHEN p_label IS NOT NULL THEN left(p_label, 3)
    ELSE left(COALESCE(p_role, '?'), 1)
  END
$function$;
COMMENT ON FUNCTION cad._abbrev(text,text) IS 'Abbreviate piece labels for display: Poteau A -> A, Traverse AB -> tAB, Lisse bas AB -> bAB, Chevron AV-1 -> V1, etc.';

CREATE OR REPLACE FUNCTION cad.add_beam(p_drawing_id integer, p_section text, p_start real[], p_end real[], p_label text DEFAULT NULL::text, p_role text DEFAULT NULL::text, p_wood_type text DEFAULT 'pin'::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_w real;
  v_h real;
  v_parts text[];
  v_dx real; v_dy real; v_dz real;
  v_length real;
  v_profile geometry;
  v_solid geometry;
BEGIN
  v_parts := string_to_array(p_section, 'x');
  v_w := v_parts[1]::real;
  v_h := v_parts[2]::real;

  v_dx := p_end[1] - p_start[1];
  v_dy := p_end[2] - p_start[2];
  v_dz := p_end[3] - p_start[3];
  v_length := sqrt(v_dx*v_dx + v_dy*v_dy + v_dz*v_dz);

  IF v_length < 1 THEN
    RAISE EXCEPTION 'beam length must be > 0, got start=% end=%', p_start, p_end;
  END IF;

  -- Profile perpendicular to dominant axis, extrusion along FULL vector
  IF abs(v_dx) >= abs(v_dy) AND abs(v_dx) >= abs(v_dz) THEN
    -- X-dominant: profile in YZ plane
    v_profile := ST_MakePolygon(ST_MakeLine(ARRAY[
      ST_MakePoint(p_start[1], p_start[2], p_start[3]),
      ST_MakePoint(p_start[1], p_start[2] + v_w, p_start[3]),
      ST_MakePoint(p_start[1], p_start[2] + v_w, p_start[3] + v_h),
      ST_MakePoint(p_start[1], p_start[2], p_start[3] + v_h),
      ST_MakePoint(p_start[1], p_start[2], p_start[3])
    ]));
  ELSIF abs(v_dy) >= abs(v_dx) AND abs(v_dy) >= abs(v_dz) THEN
    -- Y-dominant: profile in XZ plane
    v_profile := ST_MakePolygon(ST_MakeLine(ARRAY[
      ST_MakePoint(p_start[1], p_start[2], p_start[3]),
      ST_MakePoint(p_start[1] + v_w, p_start[2], p_start[3]),
      ST_MakePoint(p_start[1] + v_w, p_start[2], p_start[3] + v_h),
      ST_MakePoint(p_start[1], p_start[2], p_start[3] + v_h),
      ST_MakePoint(p_start[1], p_start[2], p_start[3])
    ]));
  ELSE
    -- Z-dominant: profile in XY plane
    v_profile := ST_MakePolygon(ST_MakeLine(ARRAY[
      ST_MakePoint(p_start[1], p_start[2], p_start[3]),
      ST_MakePoint(p_start[1] + v_w, p_start[2], p_start[3]),
      ST_MakePoint(p_start[1] + v_w, p_start[2] + v_h, p_start[3]),
      ST_MakePoint(p_start[1], p_start[2] + v_h, p_start[3]),
      ST_MakePoint(p_start[1], p_start[2], p_start[3])
    ]));
  END IF;

  -- Extrude along FULL direction vector (supports diagonals)
  v_solid := ST_Extrude(v_profile, v_dx, v_dy, v_dz);

  INSERT INTO cad.piece (drawing_id, label, role, wood_type, section, length_mm, profile, geom)
  VALUES (p_drawing_id, p_label, p_role, p_wood_type, p_section, v_length, v_profile, v_solid)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION cad.add_beam(integer,text,real[],real[],text,text,text) IS 'Creer une piece 3D entre deux points. Profil perpendiculaire, extrusion vecteur complet (diagonales supportees).';

CREATE OR REPLACE FUNCTION cad.add_piece(p_drawing_id integer, p_section text, p_length_mm real, p_position real[] DEFAULT ARRAY[0, 0, 0], p_rotation real[] DEFAULT ARRAY[0, 0, 0], p_label text DEFAULT NULL::text, p_role text DEFAULT NULL::text, p_wood_type text DEFAULT 'pin'::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_w real;
  v_h real;
  v_profile geometry;
  v_solid geometry;
  v_parts text[];
BEGIN
  -- Parse section "60x90" -> w=60, h=90
  v_parts := string_to_array(p_section, 'x');
  IF array_length(v_parts, 1) <> 2 THEN
    RAISE EXCEPTION 'section must be WxH (e.g. 60x90), got: %', p_section;
  END IF;
  v_w := v_parts[1]::real;
  v_h := v_parts[2]::real;

  -- Profil 2D (rectangle en Z=0)
  v_profile := ST_MakePolygon(ST_MakeLine(ARRAY[
    ST_MakePoint(0, 0, 0),
    ST_MakePoint(v_w, 0, 0),
    ST_MakePoint(v_w, v_h, 0),
    ST_MakePoint(0, v_h, 0),
    ST_MakePoint(0, 0, 0)
  ]));

  -- Extrusion le long de Z
  v_solid := ST_Extrude(v_profile, 0, 0, p_length_mm);

  -- Rotation (rz, ry, rx en degrés)
  IF p_rotation[3] <> 0 THEN
    v_solid := ST_RotateX(v_solid, radians(p_rotation[3]));
    v_profile := ST_RotateX(v_profile, radians(p_rotation[3]));
  END IF;
  IF p_rotation[2] <> 0 THEN
    v_solid := ST_RotateY(v_solid, radians(p_rotation[2]));
    v_profile := ST_RotateY(v_profile, radians(p_rotation[2]));
  END IF;
  IF p_rotation[1] <> 0 THEN
    v_solid := ST_RotateZ(v_solid, radians(p_rotation[1]));
    v_profile := ST_RotateZ(v_profile, radians(p_rotation[1]));
  END IF;

  -- Translation
  IF p_position[1] <> 0 OR p_position[2] <> 0 OR p_position[3] <> 0 THEN
    v_solid := ST_Translate(v_solid, p_position[1], p_position[2], p_position[3]);
    v_profile := ST_Translate(v_profile, p_position[1], p_position[2], p_position[3]);
  END IF;

  INSERT INTO cad.piece (drawing_id, label, role, wood_type, section, length_mm, profile, geom)
  VALUES (p_drawing_id, p_label, p_role, p_wood_type, p_section, p_length_mm, v_profile, v_solid)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION cad.add_piece(integer,text,real,real[],real[],text,text,text) IS 'Creer une piece 3D par position+rotation (obsolete, utiliser add_beam).';

CREATE OR REPLACE FUNCTION cad.add_shape(p_drawing_id integer, p_layer_id integer, p_type text, p_geometry jsonb, p_props jsonb DEFAULT '{}'::jsonb, p_label text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_order int;
BEGIN
  SELECT COALESCE(max(sort_order), 0) + 1 INTO v_order
  FROM cad.shape WHERE drawing_id = p_drawing_id;

  INSERT INTO cad.shape (drawing_id, layer_id, type, geometry, props, label, sort_order)
  VALUES (p_drawing_id, p_layer_id, p_type, p_geometry, p_props, p_label, v_order)
  RETURNING id INTO v_id;

  UPDATE cad.drawing SET updated_at = now() WHERE id = p_drawing_id;

  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION cad.add_shape(integer,integer,text,jsonb,jsonb,text) IS 'Ajouter une shape 2D (line, rect, circle, arc, polyline, text, dimension).';

CREATE OR REPLACE FUNCTION cad.assembly_order(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_out text := 'Assembly Order — Drawing #' || p_drawing_id || E'\n';
  v_step int := 0;
  v_placed int[] := '{}';
  v_remaining int[];
  v_next_id int;
  v_total int;
  v_iter int := 0;
BEGIN
  SELECT array_agg(id ORDER BY id) INTO v_remaining
  FROM cad.piece WHERE drawing_id = p_drawing_id;

  IF v_remaining IS NULL THEN
    RETURN 'no pieces in drawing #' || p_drawing_id;
  END IF;

  v_total := array_length(v_remaining, 1);
  v_out := v_out || v_total || ' pieces to assemble' || E'\n';
  v_out := v_out || '========================================' || E'\n';

  WHILE array_length(v_remaining, 1) > 0 AND v_iter < 100 LOOP
    v_iter := v_iter + 1;
    v_next_id := NULL;

    IF v_step = 0 THEN
      SELECT id INTO v_next_id
      FROM cad.piece
      WHERE id = ANY(v_remaining)
      ORDER BY ST_ZMin(geom), id
      LIMIT 1;
    ELSE
      SELECT p.id INTO v_next_id
      FROM cad.piece p
      WHERE p.id = ANY(v_remaining)
      ORDER BY
        (SELECT count(*) FROM cad.piece p2
         WHERE p2.id = ANY(v_placed) AND ST_3DIntersects(p.geom, p2.geom)) DESC,
        ST_ZMin(p.geom) ASC,
        p.id ASC
      LIMIT 1;
    END IF;

    IF v_next_id IS NULL THEN EXIT; END IF;

    v_step := v_step + 1;

    SELECT * INTO v_rec FROM cad.piece WHERE id = v_next_id;
    v_out := v_out || E'\nStep ' || v_step || ': '
      || coalesce(v_rec.label, '#' || v_next_id) || ' [' || v_rec.role || '] '
      || v_rec.section || ' L=' || v_rec.length_mm || 'mm';

    IF v_step = 1 THEN
      v_out := v_out || E'\n  -> Place on ground at ['
        || round(ST_XMin(v_rec.geom)::numeric,0) || ', '
        || round(ST_YMin(v_rec.geom)::numeric,0) || ', '
        || round(ST_ZMin(v_rec.geom)::numeric,0) || ']';
    ELSE
      FOR v_rec IN
        SELECT p2.id, p2.label, p2.role
        FROM cad.piece p2
        WHERE p2.id = ANY(v_placed)
          AND ST_3DIntersects(p2.geom, (SELECT geom FROM cad.piece WHERE id = v_next_id))
        ORDER BY p2.id
      LOOP
        v_out := v_out || E'\n  -> Connect to ' || coalesce(v_rec.label, '#' || v_rec.id) || ' [' || v_rec.role || ']';
      END LOOP;
    END IF;

    v_placed := v_placed || v_next_id;
    v_remaining := array_remove(v_remaining, v_next_id);
  END LOOP;

  v_out := v_out || E'\n\n========================================';
  v_out := v_out || E'\nDone: ' || v_step || '/' || v_total || ' pieces assembled';

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.assembly_order(integer) IS 'Ordre de montage: sequence bottom-up basee sur les connexions 3D.';

CREATE OR REPLACE FUNCTION cad.bill_of_materials(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_out text := '';
  v_total_vol float := 0;
  v_total_len float := 0;
  v_count int := 0;
BEGIN
  v_out := 'Bill of Materials — Drawing #' || p_drawing_id || E'\n';
  v_out := v_out || '========================================' || E'\n';

  FOR v_rec IN
    SELECT
      role,
      section,
      wood_type,
      count(*) AS qty,
      round(sum(length_mm)::numeric) AS total_length_mm,
      round((sum(ST_Volume(geom)) / 1e9)::numeric, 6) AS total_vol_m3
    FROM cad.piece
    WHERE drawing_id = p_drawing_id
    GROUP BY role, section, wood_type
    ORDER BY role, section
  LOOP
    v_out := v_out || v_rec.qty || 'x ' || v_rec.section || ' ' || v_rec.wood_type
      || ' [' || v_rec.role || ']'
      || '  L=' || v_rec.total_length_mm || 'mm'
      || '  V=' || v_rec.total_vol_m3 || ' m3'
      || E'\n';
    v_total_vol := v_total_vol + v_rec.total_vol_m3;
    v_total_len := v_total_len + v_rec.total_length_mm;
    v_count := v_count + v_rec.qty;
  END LOOP;

  v_out := v_out || '----------------------------------------' || E'\n';
  v_out := v_out || 'Total: ' || v_count || ' pieces'
    || '  L=' || round(v_total_len::numeric) || 'mm'
    || '  V=' || round(v_total_vol::numeric, 6) || ' m3';

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.bill_of_materials(integer) IS 'Liste de debit: pieces groupees par role/section/essence avec volumes PostGIS.';

CREATE OR REPLACE FUNCTION cad."check"(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_out text := '';
  v_rec record;
  v_issues int := 0;
  v_orphans int := 0;
BEGIN
  -- 1. Collisions (pièces qui se chevauchent en volume, pas juste se touchent)
  FOR v_rec IN
    SELECT a.label AS a_label, b.label AS b_label,
      round(ST_Volume(ST_3DIntersection(a.geom, b.geom))::numeric) AS overlap_vol
    FROM cad.piece a, cad.piece b
    WHERE a.drawing_id = p_drawing_id AND b.drawing_id = p_drawing_id
      AND a.id < b.id AND ST_3DIntersects(a.geom, b.geom)
  LOOP
    IF v_rec.overlap_vol > 100 THEN  -- > 100mm³ = vraie collision, pas juste un contact
      v_out := v_out || format('  COLLISION: %s & %s overlap %s mm3',
        v_rec.a_label, v_rec.b_label, v_rec.overlap_vol) || E'\n';
      v_issues := v_issues + 1;
    END IF;
  END LOOP;

  -- 2. Pièces orphelines (ne touchent aucune autre pièce)
  FOR v_rec IN
    SELECT p.id, p.label
    FROM cad.piece p
    WHERE p.drawing_id = p_drawing_id
      AND NOT EXISTS (
        SELECT 1 FROM cad.piece o
        WHERE o.drawing_id = p_drawing_id AND o.id <> p.id
          AND ST_3DIntersects(p.geom, o.geom)
      )
  LOOP
    v_out := v_out || format('  ORPHAN: %s is not connected to any piece', v_rec.label) || E'\n';
    v_orphans := v_orphans + 1;
  END LOOP;

  -- 3. Pièces sous le sol (z < 0)
  FOR v_rec IN
    SELECT label, round(ST_ZMin(geom)::numeric) AS z_min
    FROM cad.piece WHERE drawing_id = p_drawing_id AND ST_ZMin(geom) < -1
  LOOP
    v_out := v_out || format('  UNDERGROUND: %s z_min=%smm', v_rec.label, v_rec.z_min) || E'\n';
    v_issues := v_issues + 1;
  END LOOP;

  -- 4. Pièces flottantes (ne touchent pas le sol et ne sont connectées qu'à des pièces flottantes)
  -- Simplifié: pièces dont z_min > 0 et qui ne touchent aucune pièce au sol
  FOR v_rec IN
    SELECT p.id, p.label, round(ST_ZMin(p.geom)::numeric) AS z_min
    FROM cad.piece p
    WHERE p.drawing_id = p_drawing_id
      AND ST_ZMin(p.geom) > 1  -- pas au sol
      AND NOT EXISTS (
        SELECT 1 FROM cad.piece ground
        WHERE ground.drawing_id = p_drawing_id
          AND ground.id <> p.id
          AND ST_ZMin(ground.geom) < 1  -- pièce au sol
          AND ST_3DIntersects(p.geom, ground.geom)
      )
  LOOP
    v_out := v_out || format('  FLOATING: %s at z=%smm not connected to ground', v_rec.label, v_rec.z_min) || E'\n';
    v_issues := v_issues + 1;
  END LOOP;

  IF v_out = '' THEN
    RETURN format('check: OK (%s pieces, 0 issues)', (SELECT count(*) FROM cad.piece WHERE drawing_id = p_drawing_id));
  END IF;

  RETURN format('check: %s issues found', v_issues + v_orphans) || E'\n' || v_out;
END;
$function$;
COMMENT ON FUNCTION cad."check"(integer) IS 'Validation structurelle: collisions (>100mm3), orphelins, pieces souterraines ou flottantes.';

CREATE OR REPLACE FUNCTION cad.clear_drawing(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int;
BEGIN
  DELETE FROM cad.piece WHERE drawing_id = p_drawing_id;
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN 'cleared: ' || v_count || ' pieces removed from drawing #' || p_drawing_id;
END;
$function$;
COMMENT ON FUNCTION cad.clear_drawing(integer) IS 'Supprimer toutes les pieces d un dessin.';

CREATE OR REPLACE FUNCTION cad.cross_section(p_drawing_id integer, p_axis text, p_value double precision)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_out text := 'Cross section at ' || p_axis || '=' || p_value || 'mm' || E'\n';
  v_count int := 0;
BEGIN
  FOR v_rec IN
    SELECT id, label, role, section,
           round(ST_XMin(geom)::numeric,1) AS x1, round(ST_YMin(geom)::numeric,1) AS y1, round(ST_ZMin(geom)::numeric,1) AS z1,
           round(ST_XMax(geom)::numeric,1) AS x2, round(ST_YMax(geom)::numeric,1) AS y2, round(ST_ZMax(geom)::numeric,1) AS z2
    FROM cad.piece
    WHERE drawing_id = p_drawing_id
      AND CASE p_axis
            WHEN 'x' THEN ST_XMin(geom) <= p_value AND ST_XMax(geom) >= p_value
            WHEN 'y' THEN ST_YMin(geom) <= p_value AND ST_YMax(geom) >= p_value
            WHEN 'z' THEN ST_ZMin(geom) <= p_value AND ST_ZMax(geom) >= p_value
          END
    ORDER BY id
  LOOP
    v_count := v_count + 1;
    v_out := v_out || '  #' || v_rec.id || ' ' || coalesce(v_rec.label, '') || ' [' || v_rec.role || '] ' || v_rec.section
      || '  bbox:[' || v_rec.x1 || ',' || v_rec.y1 || ',' || v_rec.z1
      || ']->[' || v_rec.x2 || ',' || v_rec.y2 || ',' || v_rec.z2 || ']'
      || E'\n';
  END LOOP;

  v_out := v_out || v_count || ' pieces intersected';
  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.cross_section(integer,text,double precision) IS 'Coupe du modele selon un axe (x/y/z) a une position donnee.';

CREATE OR REPLACE FUNCTION cad.delete_shape(p_shape_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing_id int;
BEGIN
  DELETE FROM cad.shape WHERE id = p_shape_id RETURNING drawing_id INTO v_drawing_id;
  IF v_drawing_id IS NOT NULL THEN
    UPDATE cad.drawing SET updated_at = now() WHERE id = v_drawing_id;
  END IF;
END;
$function$;
COMMENT ON FUNCTION cad.delete_shape(integer) IS 'Supprimer une shape 2D.';

CREATE OR REPLACE FUNCTION cad.drawing_add(name text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  IF name IS NULL OR trim(name) = '' THEN
    RETURN '<template data-toast="error">Nom requis</template>';
  END IF;

  INSERT INTO cad.drawing (name) VALUES (trim(name)) RETURNING id INTO v_id;

  -- Créer un calque par défaut
  INSERT INTO cad.layer (drawing_id, name, color, stroke_width)
  VALUES (v_id, 'Structure', '#333333', 1.5);

  RETURN format('<template data-redirect="/drawing/%s"></template>', v_id);
END;
$function$;
COMMENT ON FUNCTION cad.drawing_add(text) IS 'Creer un nouveau dessin.';

CREATE OR REPLACE FUNCTION cad.faces(p_piece_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_p cad.piece;
  v_xmin float; v_ymin float; v_zmin float;
  v_xmax float; v_ymax float; v_zmax float;
BEGIN
  SELECT * INTO v_p FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_piece_id || ' not found'; END IF;

  v_xmin := ST_XMin(v_p.geom); v_ymin := ST_YMin(v_p.geom); v_zmin := ST_ZMin(v_p.geom);
  v_xmax := ST_XMax(v_p.geom); v_ymax := ST_YMax(v_p.geom); v_zmax := ST_ZMax(v_p.geom);

  RETURN coalesce(v_p.label, '#' || p_piece_id) || ' faces:'
    || E'\n  top:    z=' || round(v_zmax::numeric, 1)
    || E'\n  bottom: z=' || round(v_zmin::numeric, 1)
    || E'\n  left:   x=' || round(v_xmin::numeric, 1)
    || E'\n  right:  x=' || round(v_xmax::numeric, 1)
    || E'\n  front:  y=' || round(v_ymin::numeric, 1)
    || E'\n  back:   y=' || round(v_ymax::numeric, 1)
    || E'\n  size:   ' || round((v_xmax - v_xmin)::numeric, 1) || ' x '
                       || round((v_ymax - v_ymin)::numeric, 1) || ' x '
                       || round((v_zmax - v_zmin)::numeric, 1) || ' mm';
END;
$function$;
COMMENT ON FUNCTION cad.faces(integer) IS 'Faces de la bounding box (top/bottom/left/right/front/back) avec coordonnees.';

CREATE OR REPLACE FUNCTION cad.group_shapes(p_drawing_id integer, p_shape_ids integer[], p_name text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_layer_id int;
  v_group_id int;
BEGIN
  -- Vérifier que tous les shapes existent et appartiennent au même dessin
  IF NOT EXISTS (
    SELECT 1 FROM cad.shape 
    WHERE id = ANY(p_shape_ids) AND drawing_id = p_drawing_id
    HAVING count(*) = array_length(p_shape_ids, 1)
  ) THEN
    RAISE EXCEPTION 'Certains shapes sont invalides ou n''appartiennent pas au dessin %', p_drawing_id;
  END IF;

  -- Prendre le layer du premier shape
  SELECT layer_id INTO v_layer_id FROM cad.shape WHERE id = p_shape_ids[1];

  -- Créer le shape group
  INSERT INTO cad.shape (drawing_id, layer_id, type, geometry, label)
  VALUES (p_drawing_id, v_layer_id, 'group', '{}', p_name)
  RETURNING id INTO v_group_id;

  -- Rattacher les shapes au group
  UPDATE cad.shape SET parent_id = v_group_id WHERE id = ANY(p_shape_ids);

  RETURN v_group_id;
END;
$function$;
COMMENT ON FUNCTION cad.group_shapes(integer,integer[],text) IS 'Groupe plusieurs shapes ensemble. Retourne l''id du groupe créé.';

CREATE OR REPLACE FUNCTION cad.help(p_filter text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_out text := 'CAD Spatial Toolbox' || E'\n';
BEGIN
  v_out := v_out || '===================' || E'\n';

  FOR v_rec IN
    SELECT p.proname AS name,
           pg_catalog.pg_get_function_identity_arguments(p.oid) AS args,
           d.description AS doc
    FROM pg_catalog.pg_proc p
    JOIN pg_catalog.pg_namespace n ON n.oid = p.pronamespace
    LEFT JOIN pg_catalog.pg_description d ON d.objoid = p.oid
    WHERE n.nspname = 'cad'
      AND (p_filter IS NULL OR p.proname ILIKE '%' || p_filter || '%'
           OR coalesce(d.description, '') ILIKE '%' || p_filter || '%')
    ORDER BY p.proname
  LOOP
    v_out := v_out || E'\n' || v_rec.name || '(' || v_rec.args || ')'
      || E'\n  ' || coalesce(v_rec.doc, '(no description)')
      || E'\n';
  END LOOP;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.help(text) IS 'Liste les fonctions cad avec leur documentation. Filtre optionnel.';

CREATE OR REPLACE FUNCTION cad.inspect(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_out text := '';
  v_piece record;
  v_joint record;
  v_bbox text;
  v_total_vol real;
  v_count int;
BEGIN
  -- Header
  SELECT count(*), round(sum(ST_Volume(geom))::numeric / 1e9, 4)
  INTO v_count, v_total_vol
  FROM cad.piece WHERE drawing_id = p_drawing_id;

  IF v_count = 0 THEN RETURN 'empty model'; END IF;

  -- Bounding box global
  SELECT format('bbox: [%s, %s, %s] -> [%s, %s, %s]  size: %s x %s x %s mm',
    round(ST_XMin(ext)::numeric), round(ST_YMin(ext)::numeric), round(ST_ZMin(ext)::numeric),
    round(ST_XMax(ext)::numeric), round(ST_YMax(ext)::numeric), round(ST_ZMax(ext)::numeric),
    round((ST_XMax(ext) - ST_XMin(ext))::numeric),
    round((ST_YMax(ext) - ST_YMin(ext))::numeric),
    round((ST_ZMax(ext) - ST_ZMin(ext))::numeric)
  ) INTO v_bbox
  FROM (SELECT ST_3DExtent(geom)::geometry AS ext FROM cad.piece WHERE drawing_id = p_drawing_id) sub;

  v_out := format('model: %s pieces, %s m3 bois', v_count, v_total_vol) || E'\n' || v_bbox || E'\n\n';

  -- Pieces
  v_out := v_out || 'pieces:' || E'\n';
  FOR v_piece IN
    SELECT id, label, role, wood_type, section, length_mm,
      round(ST_XMin(geom)::numeric) AS x0, round(ST_YMin(geom)::numeric) AS y0, round(ST_ZMin(geom)::numeric) AS z0,
      round(ST_XMax(geom)::numeric) AS x1, round(ST_YMax(geom)::numeric) AS y1, round(ST_ZMax(geom)::numeric) AS z1,
      round((ST_Volume(geom) / 1e9)::numeric, 6) AS vol_m3
    FROM cad.piece WHERE drawing_id = p_drawing_id ORDER BY id
  LOOP
    v_out := v_out || format('  #%s %s [%s] %s %smm  pos:[%s,%s,%s]->[%s,%s,%s]  vol:%s m3',
      v_piece.id, COALESCE(v_piece.label, '-'), v_piece.role,
      v_piece.section, v_piece.length_mm::int,
      v_piece.x0, v_piece.y0, v_piece.z0,
      v_piece.x1, v_piece.y1, v_piece.z1,
      v_piece.vol_m3
    ) || E'\n';
  END LOOP;

  -- Joints (touching pairs)
  v_out := v_out || E'\n' || 'joints:' || E'\n';
  FOR v_joint IN
    SELECT a.id AS a_id, a.label AS a_label, b.id AS b_id, b.label AS b_label,
      ST_3DIntersects(a.geom, b.geom) AS touches
    FROM cad.piece a, cad.piece b
    WHERE a.drawing_id = p_drawing_id AND b.drawing_id = p_drawing_id AND a.id < b.id
    ORDER BY a.id, b.id
  LOOP
    IF v_joint.touches THEN
      v_out := v_out || format('  %s <-> %s : connected',
        COALESCE(v_joint.a_label, '#' || v_joint.a_id),
        COALESCE(v_joint.b_label, '#' || v_joint.b_id)
      ) || E'\n';
    END IF;
  END LOOP;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.inspect(integer) IS 'Vue complete du modele: pieces, bbox, volume, joints entre pieces.';

CREATE OR REPLACE FUNCTION cad.duplicate_piece(p_piece_id integer, p_dx double precision DEFAULT 0, p_dy double precision DEFAULT 0, p_dz double precision DEFAULT 0, p_label text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src cad.piece;
  v_new_id int;
BEGIN
  SELECT * INTO v_src FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_piece_id || ' not found'; END IF;

  INSERT INTO cad.piece (drawing_id, label, role, wood_type, section, length_mm, profile, geom)
  VALUES (
    v_src.drawing_id,
    coalesce(p_label, v_src.label || ' (copy)'),
    v_src.role,
    v_src.wood_type,
    v_src.section,
    v_src.length_mm,
    ST_Translate(v_src.profile, p_dx, p_dy, p_dz),
    ST_Translate(v_src.geom, p_dx, p_dy, p_dz)
  )
  RETURNING id INTO v_new_id;

  RETURN 'duplicated: #' || p_piece_id || ' -> #' || v_new_id
    || ' ' || coalesce(p_label, v_src.label || ' (copy)')
    || E'\noffset: [' || p_dx || ', ' || p_dy || ', ' || p_dz || ']'
    || E'\n' || cad.inspect(v_src.drawing_id);
END;
$function$;
COMMENT ON FUNCTION cad.duplicate_piece(integer,double precision,double precision,double precision,text) IS 'Dupliquer une piece avec offset de translation.';

CREATE OR REPLACE FUNCTION cad.list_pieces(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_out text := '';
BEGIN
  FOR v_rec IN
    SELECT id, label, role, section, length_mm, wood_type,
           round(ST_XMin(geom)::numeric,1) AS x1, round(ST_YMin(geom)::numeric,1) AS y1, round(ST_ZMin(geom)::numeric,1) AS z1,
           round(ST_XMax(geom)::numeric,1) AS x2, round(ST_YMax(geom)::numeric,1) AS y2, round(ST_ZMax(geom)::numeric,1) AS z2
    FROM cad.piece
    WHERE drawing_id = p_drawing_id
    ORDER BY id
  LOOP
    v_out := v_out || '#' || v_rec.id || ' ' || coalesce(v_rec.label, '(unnamed)')
      || ' [' || v_rec.role || '] ' || v_rec.section || ' ' || v_rec.wood_type
      || ' L=' || v_rec.length_mm || 'mm'
      || '  [' || v_rec.x1 || ',' || v_rec.y1 || ',' || v_rec.z1
      || ']->[' || v_rec.x2 || ',' || v_rec.y2 || ',' || v_rec.z2 || ']'
      || E'\n';
  END LOOP;

  IF v_out = '' THEN RETURN 'no pieces in drawing #' || p_drawing_id; END IF;
  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.list_pieces(integer) IS 'Liste rapide des pieces avec position bbox.';

CREATE OR REPLACE FUNCTION cad.measure(p_a integer, p_b integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_a cad.piece;
  v_b cad.piece;
  v_dist float;
  v_touches boolean;
BEGIN
  SELECT * INTO v_a FROM cad.piece WHERE id = p_a;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_a || ' not found'; END IF;
  SELECT * INTO v_b FROM cad.piece WHERE id = p_b;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_b || ' not found'; END IF;

  v_dist := ST_3DDistance(v_a.geom, v_b.geom);
  v_touches := ST_3DIntersects(v_a.geom, v_b.geom);

  RETURN coalesce(v_a.label, '#' || p_a) || ' <-> ' || coalesce(v_b.label, '#' || p_b)
    || E'\ndistance: ' || round(v_dist::numeric, 1) || ' mm'
    || E'\ntouching: ' || CASE WHEN v_touches THEN 'yes' ELSE 'no' END;
END;
$function$;
COMMENT ON FUNCTION cad.measure(integer,integer) IS 'Distance 3D et contact entre deux pieces.';

CREATE OR REPLACE FUNCTION cad.move_group(p_group_id integer, p_dx real, p_dy real)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int;
  v_child record;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM cad.shape WHERE id = p_group_id AND type = 'group') THEN
    RAISE EXCEPTION 'Shape % n''est pas un groupe', p_group_id;
  END IF;

  v_count := 0;
  FOR v_child IN
    SELECT id, type, geometry FROM cad.shape WHERE parent_id = p_group_id
  LOOP
    IF v_child.type = 'group' THEN
      -- Récursif pour les sous-groupes
      PERFORM cad.move_group(v_child.id, p_dx, p_dy);
    ELSE
      PERFORM cad.move_shape(v_child.id, p_dx, p_dy);
    END IF;
    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION cad.move_group(integer,real,real) IS 'Déplace tous les shapes d''un groupe (récursif pour sous-groupes).';

CREATE OR REPLACE FUNCTION cad.move_piece(p_piece_id integer, p_dx real DEFAULT 0, p_dy real DEFAULT 0, p_dz real DEFAULT 0)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_piece cad.piece;
BEGIN
  SELECT * INTO v_piece FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'piece not found'; END IF;

  UPDATE cad.piece SET
    geom = ST_Translate(geom, p_dx, p_dy, p_dz),
    profile = ST_Translate(profile, p_dx, p_dy, p_dz)
  WHERE id = p_piece_id;

  RETURN format('moved %s by [%s, %s, %s] -> now [%s,%s,%s]->[%s,%s,%s]',
    v_piece.label, p_dx, p_dy, p_dz,
    round((ST_XMin(v_piece.geom) + p_dx)::numeric),
    round((ST_YMin(v_piece.geom) + p_dy)::numeric),
    round((ST_ZMin(v_piece.geom) + p_dz)::numeric),
    round((ST_XMax(v_piece.geom) + p_dx)::numeric),
    round((ST_YMax(v_piece.geom) + p_dy)::numeric),
    round((ST_ZMax(v_piece.geom) + p_dz)::numeric)
  );
END;
$function$;
COMMENT ON FUNCTION cad.move_piece(integer,real,real,real) IS 'Translater une piece via ST_Translate.';

CREATE OR REPLACE FUNCTION cad.move_shape(p_shape_id integer, p_dx real, p_dy real)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_shape cad.shape;
  v_g jsonb;
  v_pts jsonb;
BEGIN
  SELECT * INTO v_shape FROM cad.shape WHERE id = p_shape_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'shape % not found', p_shape_id; END IF;

  v_g := v_shape.geometry;

  CASE v_shape.type
    WHEN 'line', 'dimension' THEN
      v_g := jsonb_set(v_g, '{x1}', to_jsonb((v_g->>'x1')::real + p_dx));
      v_g := jsonb_set(v_g, '{y1}', to_jsonb((v_g->>'y1')::real + p_dy));
      v_g := jsonb_set(v_g, '{x2}', to_jsonb((v_g->>'x2')::real + p_dx));
      v_g := jsonb_set(v_g, '{y2}', to_jsonb((v_g->>'y2')::real + p_dy));

    WHEN 'rect' THEN
      v_g := jsonb_set(v_g, '{x}', to_jsonb((v_g->>'x')::real + p_dx));
      v_g := jsonb_set(v_g, '{y}', to_jsonb((v_g->>'y')::real + p_dy));

    WHEN 'circle', 'arc' THEN
      v_g := jsonb_set(v_g, '{cx}', to_jsonb((v_g->>'cx')::real + p_dx));
      v_g := jsonb_set(v_g, '{cy}', to_jsonb((v_g->>'cy')::real + p_dy));

    WHEN 'text' THEN
      v_g := jsonb_set(v_g, '{x}', to_jsonb((v_g->>'x')::real + p_dx));
      v_g := jsonb_set(v_g, '{y}', to_jsonb((v_g->>'y')::real + p_dy));

    WHEN 'polyline' THEN
      SELECT jsonb_agg(jsonb_build_array(
        (p->0)::real + p_dx,
        (p->1)::real + p_dy
      )) INTO v_pts
      FROM jsonb_array_elements(v_g->'points') AS p;
      v_g := jsonb_set(v_g, '{points}', v_pts);

    ELSE NULL;
  END CASE;

  UPDATE cad.shape SET geometry = v_g WHERE id = p_shape_id;
  UPDATE cad.drawing SET updated_at = now() WHERE id = v_shape.drawing_id;
END;
$function$;
COMMENT ON FUNCTION cad.move_shape(integer,real,real) IS 'Deplacer une shape 2D par dx/dy.';

CREATE OR REPLACE FUNCTION cad.nav_items()
 RETURNS jsonb
 LANGUAGE sql
AS $function$
  SELECT '[{"href":"/","label":"Dessins"}]'::jsonb;
$function$;
COMMENT ON FUNCTION cad.nav_items() IS 'Items de navigation pour le menu pgView.';

CREATE OR REPLACE FUNCTION cad.neighbors(p_piece_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_piece cad.piece;
  v_out text;
  v_rec record;
BEGIN
  SELECT * INTO v_piece FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'piece not found'; END IF;

  v_out := format('%s [%s] %s %smm', v_piece.label, v_piece.role, v_piece.section, v_piece.length_mm::int);
  v_out := v_out || format('  pos:[%s,%s,%s]->[%s,%s,%s]',
    round(ST_XMin(v_piece.geom)::numeric), round(ST_YMin(v_piece.geom)::numeric), round(ST_ZMin(v_piece.geom)::numeric),
    round(ST_XMax(v_piece.geom)::numeric), round(ST_YMax(v_piece.geom)::numeric), round(ST_ZMax(v_piece.geom)::numeric)
  ) || E'\n\n';

  v_out := v_out || 'connected to:' || E'\n';
  FOR v_rec IN
    SELECT o.id, o.label, o.role,
      round(ST_3DDistance(v_piece.geom, o.geom)::numeric, 1) AS dist,
      CASE
        WHEN ST_ZMax(o.geom) <= ST_ZMin(v_piece.geom) + 1 THEN 'below'
        WHEN ST_ZMin(o.geom) >= ST_ZMax(v_piece.geom) - 1 THEN 'above'
        WHEN ST_XMax(o.geom) <= ST_XMin(v_piece.geom) + 1 THEN 'left'
        WHEN ST_XMin(o.geom) >= ST_XMax(v_piece.geom) - 1 THEN 'right'
        ELSE 'side'
      END AS direction
    FROM cad.piece o
    WHERE o.drawing_id = v_piece.drawing_id AND o.id <> v_piece.id
      AND ST_3DIntersects(v_piece.geom, o.geom)
    ORDER BY o.id
  LOOP
    v_out := v_out || format('  %s [%s] -> %s', v_rec.label, v_rec.role, v_rec.direction) || E'\n';
  END LOOP;

  -- Nearest non-connected pieces
  v_out := v_out || E'\n' || 'nearest unconnected:' || E'\n';
  FOR v_rec IN
    SELECT o.id, o.label, o.role,
      round(ST_3DDistance(v_piece.geom, o.geom)::numeric, 1) AS dist
    FROM cad.piece o
    WHERE o.drawing_id = v_piece.drawing_id AND o.id <> v_piece.id
      AND NOT ST_3DIntersects(v_piece.geom, o.geom)
    ORDER BY ST_3DDistance(v_piece.geom, o.geom)
    LIMIT 3
  LOOP
    v_out := v_out || format('  %s [%s] at %smm', v_rec.label, v_rec.role, v_rec.dist) || E'\n';
  END LOOP;

  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.neighbors(integer) IS 'Pieces adjacentes avec direction (above/below/left/right), plus proche non-connectee.';

CREATE OR REPLACE FUNCTION cad.page_drawing_3d(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing cad.drawing;
BEGIN
  SELECT * INTO v_drawing FROM cad.drawing WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.error('404', 'Dessin non trouvé');
  END IF;

  RETURN
    '<div id="cad-viewer" style="width:100%;height:70vh;background:#1a1a2e;border-radius:8px;overflow:hidden"></div>'
    || '<script type="module">'
    || 'import * as THREE from "https://cdn.jsdelivr.net/npm/three@0.170.0/build/three.module.min.js";'
    || 'import {OrbitControls} from "https://cdn.jsdelivr.net/npm/three@0.170.0/examples/jsm/controls/OrbitControls.js";'

    -- Setup
    || 'const el=document.getElementById("cad-viewer");'
    || 'const W=el.clientWidth,H=el.clientHeight;'
    || 'const scene=new THREE.Scene();'
    || 'scene.background=new THREE.Color(0x1a1a2e);'
    || 'const camera=new THREE.PerspectiveCamera(50,W/H,1,100000);'
    || 'const renderer=new THREE.WebGLRenderer({antialias:true});'
    || 'renderer.setSize(W,H);'
    || 'renderer.setPixelRatio(window.devicePixelRatio);'
    || 'el.appendChild(renderer.domElement);'

    -- Lights
    || 'scene.add(new THREE.AmbientLight(0xffffff,0.5));'
    || 'const dl=new THREE.DirectionalLight(0xffffff,0.8);'
    || 'dl.position.set(2000,3000,4000);scene.add(dl);'
    || 'const dl2=new THREE.DirectionalLight(0xffffff,0.3);'
    || 'dl2.position.set(-1000,-2000,1000);scene.add(dl2);'

    -- Grid
    || 'const grid=new THREE.GridHelper(5000,50,0x444466,0x333355);'
    || 'grid.rotation.x=Math.PI/2;scene.add(grid);'

    -- Controls
    || 'const ctrl=new OrbitControls(camera,renderer.domElement);'
    || 'ctrl.enableDamping=true;'

    -- Colors by role
    || 'const COLORS={poteau:0xc8956c,traverse:0xa07850,chevron:0xd4a76a,lisse:0xb8925a,default:0xc8a882};'

    -- Render loop
    || 'function animate(){requestAnimationFrame(animate);ctrl.update();renderer.render(scene,camera)}'
    || 'animate();'

    -- Load scene
    || 'let lastJson="";'
    || 'async function loadScene(){'
    ||   'const r=await fetch("/rpc/scene_json",{method:"POST",'
    ||     'headers:{"Content-Type":"application/json","Accept":"application/json"},'
    ||     'body:JSON.stringify({p_drawing_id:' || p_id || '})});'
    ||   'const raw=await r.text();'
    ||   'if(raw===lastJson)return;lastJson=raw;'
    ||   'const pieces=JSON.parse(raw);'

    -- Clear old meshes
    ||   'scene.children.filter(c=>c.userData.piece).forEach(c=>scene.remove(c));'

    -- Build meshes from GeoJSON triangles
    ||   'let allVerts=[];'
    ||   'pieces.forEach(p=>{'
    ||     'const geom=new THREE.BufferGeometry();'
    ||     'const verts=[];'
    ||     'if(p.mesh&&p.mesh.geometries){'
    ||       'p.mesh.geometries.forEach(g=>{'
    ||         'if(g.coordinates&&g.coordinates[0]){'
    ||           'const ring=g.coordinates[0];'
    ||           'if(ring.length>=3){'
    ||             'verts.push(ring[0][0],ring[0][2],ring[0][1]);'  -- swap Y/Z for Three.js
    ||             'verts.push(ring[1][0],ring[1][2],ring[1][1]);'
    ||             'verts.push(ring[2][0],ring[2][2],ring[2][1]);'
    ||           '}'
    ||         '}'
    ||       '});'
    ||     '}'
    ||     'if(verts.length===0)return;'
    ||     'geom.setAttribute("position",new THREE.Float32BufferAttribute(verts,3));'
    ||     'geom.computeVertexNormals();'
    ||     'const color=COLORS[p.role]||COLORS.default;'
    ||     'const mat=new THREE.MeshPhongMaterial({color,flatShading:true});'
    ||     'const mesh=new THREE.Mesh(geom,mat);'
    ||     'mesh.userData.piece=true;'
    ||     'scene.add(mesh);'
    ||     'allVerts.push(...verts);'
    ||   '});'

    -- Center camera on model
    ||   'if(allVerts.length>0){'
    ||     'const box=new THREE.Box3();'
    ||     'for(let i=0;i<allVerts.length;i+=3){'
    ||       'box.expandByPoint(new THREE.Vector3(allVerts[i],allVerts[i+1],allVerts[i+2]));'
    ||     '}'
    ||     'const center=box.getCenter(new THREE.Vector3());'
    ||     'const size=box.getSize(new THREE.Vector3()).length();'
    ||     'ctrl.target.copy(center);'
    ||     'camera.position.copy(center.clone().add(new THREE.Vector3(size*0.8,size*0.6,size*0.8)));'
    ||     'camera.lookAt(center);'
    ||     'ctrl.update();'
    ||   '}'
    || '}'

    -- Initial load + polling
    || 'loadScene();'
    || 'setInterval(loadScene,1500);'

    -- Resize
    || 'window.addEventListener("resize",()=>{'
    ||   'const w=el.clientWidth,h=el.clientHeight;'
    ||   'camera.aspect=w/h;camera.updateProjectionMatrix();'
    ||   'renderer.setSize(w,h);'
    || '});'

    || '</script>';
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page_drawing_add(p_body jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_name text := p_body->>'name';
  v_id int;
BEGIN
  IF v_name IS NULL OR trim(v_name) = '' THEN
    RETURN '<template data-toast="error">Nom requis</template>';
  END IF;

  INSERT INTO cad.drawing (name) VALUES (trim(v_name)) RETURNING id INTO v_id;

  -- Créer un calque par défaut
  INSERT INTO cad.layer (drawing_id, name, color, stroke_width)
  VALUES (v_id, 'Structure', '#333333', 1.5);

  RETURN format('<template data-redirect="/drawing/%s"></template>', v_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page_drawing_add_shape(p_id integer, p_body jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_layer_id int := (p_body->>'layer_id')::int;
  v_type text := p_body->>'type';
  v_geometry jsonb;
  v_props jsonb;
  v_label text := nullif(trim(COALESCE(p_body->>'label', '')), '');
  v_shape_id int;
BEGIN
  IF v_layer_id IS NULL OR v_type IS NULL THEN
    RETURN '<template data-toast="error">Calque et type requis</template>';
  END IF;

  BEGIN
    v_geometry := COALESCE(p_body->>'geometry', '{}')::jsonb;
  EXCEPTION WHEN OTHERS THEN
    RETURN '<template data-toast="error">Géométrie JSON invalide</template>';
  END;

  BEGIN
    v_props := COALESCE(p_body->>'props', '{}')::jsonb;
  EXCEPTION WHEN OTHERS THEN
    RETURN '<template data-toast="error">Props JSON invalides</template>';
  END;

  v_shape_id := cad.add_shape(p_id, v_layer_id, v_type, v_geometry, v_props, v_label);

  RETURN format('<template data-toast="success">Shape #%s ajoutée</template>', v_shape_id)
    || format('<template data-redirect="/drawing/%s"></template>', p_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page_drawing_bom(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing cad.drawing;
BEGIN
  SELECT * INTO v_drawing FROM cad.drawing WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.error('404', 'Dessin non trouvé');
  END IF;

  RETURN cad.bill_of_materials(p_id)
    || format('<p><a href="/drawing/%s">Retour au plan</a></p>', p_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page_drawing_delete_shape(p_id integer, p_body jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_shape_id int := (p_body->>'shape_id')::int;
BEGIN
  IF v_shape_id IS NULL THEN
    RETURN '<template data-toast="error">shape_id requis</template>';
  END IF;

  PERFORM cad.delete_shape(v_shape_id);

  RETURN format('<template data-toast="success">Shape #%s supprimée</template>', v_shape_id)
    || format('<template data-redirect="/drawing/%s"></template>', p_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page_index()
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_drawings text;
BEGIN
  SELECT string_agg(
    pgv.card(
      d.name,
      format('%s × %s %s — échelle 1:%s', d.width, d.height, d.unit, d.scale),
      format('<a href="/drawing/%s">Ouvrir</a>', d.id)
    ), E'\n' ORDER BY d.updated_at DESC
  ) INTO v_drawings
  FROM cad.drawing d;

  v_body := COALESCE(v_drawings, '<p>Aucun dessin. Créez-en un ci-dessous.</p>');

  v_body := v_body ||
    '<form data-rpc="drawing_add">'
    '<fieldset role="group">'
    || pgv.input('name', 'text', 'Nom du dessin')
    || '<button type="submit">Nouveau dessin</button>'
    '</fieldset>'
    '</form>';

  RETURN v_body;
END;
$function$;

CREATE OR REPLACE FUNCTION cad.remove_piece(p_piece_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_label text;
  v_drawing_id int;
BEGIN
  SELECT label, drawing_id INTO v_label, v_drawing_id
  FROM cad.piece WHERE id = p_piece_id;

  IF NOT FOUND THEN
    RETURN 'error: piece #' || p_piece_id || ' not found';
  END IF;

  DELETE FROM cad.piece WHERE id = p_piece_id;

  RETURN 'removed: ' || coalesce(v_label, '#' || p_piece_id)
    || E'\n' || cad.inspect(v_drawing_id);
END;
$function$;
COMMENT ON FUNCTION cad.remove_piece(integer) IS 'Supprimer une piece et afficher l etat du modele.';

CREATE OR REPLACE FUNCTION cad.render_arc(p_g jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cx real := (p_g->>'cx')::real;
  v_cy real := (p_g->>'cy')::real;
  v_r  real := (p_g->>'r')::real;
  v_sa real := (p_g->>'start_angle')::real;
  v_ea real := (p_g->>'end_angle')::real;
  v_x1 real; v_y1 real; v_x2 real; v_y2 real;
  v_large int;
BEGIN
  v_x1 := v_cx + v_r * cos(radians(v_sa));
  v_y1 := v_cy + v_r * sin(radians(v_sa));
  v_x2 := v_cx + v_r * cos(radians(v_ea));
  v_y2 := v_cy + v_r * sin(radians(v_ea));
  v_large := CASE WHEN abs(v_ea - v_sa) > 180 THEN 1 ELSE 0 END;

  RETURN format('<path d="M %s %s A %s %s 0 %s 1 %s %s"/>',
    v_x1, v_y1, v_r, v_r, v_large, v_x2, v_y2);
END;
$function$;
COMMENT ON FUNCTION cad.render_arc(jsonb) IS 'Rendu SVG d un arc de cercle.';

CREATE OR REPLACE FUNCTION cad.render_dimension(p_g jsonb, p_unit text DEFAULT 'mm'::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_x1 real := (p_g->>'x1')::real;
  v_y1 real := (p_g->>'y1')::real;
  v_x2 real := (p_g->>'x2')::real;
  v_y2 real := (p_g->>'y2')::real;
  v_offset real := COALESCE((p_g->>'offset')::real, 20);
  v_dist real;
  v_mx real; v_my real;
  v_dx real; v_dy real; v_len real;
  v_nx real; v_ny real;
  v_ox1 real; v_oy1 real; v_ox2 real; v_oy2 real;
BEGIN
  -- Distance entre les deux points
  v_dist := sqrt((v_x2-v_x1)^2 + (v_y2-v_y1)^2);

  -- Vecteur direction normalisé
  v_dx := v_x2 - v_x1;
  v_dy := v_y2 - v_y1;
  v_len := sqrt(v_dx^2 + v_dy^2);
  IF v_len = 0 THEN RETURN ''; END IF;

  -- Normal perpendiculaire
  v_nx := -v_dy / v_len * v_offset;
  v_ny :=  v_dx / v_len * v_offset;

  -- Points de la ligne de cote (décalée)
  v_ox1 := v_x1 + v_nx; v_oy1 := v_y1 + v_ny;
  v_ox2 := v_x2 + v_nx; v_oy2 := v_y2 + v_ny;

  -- Milieu pour le texte
  v_mx := (v_ox1 + v_ox2) / 2;
  v_my := (v_oy1 + v_oy2) / 2;

  RETURN
    -- Lignes d'attache
    format('<line x1="%s" y1="%s" x2="%s" y2="%s" stroke-dasharray="4 2"/>',
      v_x1, v_y1, v_ox1, v_oy1)
    || format('<line x1="%s" y1="%s" x2="%s" y2="%s" stroke-dasharray="4 2"/>',
      v_x2, v_y2, v_ox2, v_oy2)
    -- Ligne de cote
    || format('<line x1="%s" y1="%s" x2="%s" y2="%s" marker-start="url(#arrow)" marker-end="url(#arrow)"/>',
      v_ox1, v_oy1, v_ox2, v_oy2)
    -- Texte de la mesure
    || format('<text x="%s" y="%s" font-size="12" text-anchor="middle" fill="currentColor" stroke="none" dy="-4">%s %s</text>',
      v_mx, v_my, round(v_dist::numeric, 1), p_unit);
END;
$function$;
COMMENT ON FUNCTION cad.render_dimension(jsonb,text) IS 'Rendu SVG d une cote (ligne + texte mesure).';

CREATE OR REPLACE FUNCTION cad.render_perspective(p_drawing_id integer, p_piece_ids integer[], p_mvp real[], p_width integer DEFAULT 900, p_height integer DEFAULT 700)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_svg text;
  v_color text;
  v_label text;
  -- Box corners in Three.js space (8 per piece)
  v_corners float[8][3];
  v_screen float[8][2];
  v_clip_w float;
  v_cx float; v_cy float; v_cz float;
  v_sx float; v_sy float;
  v_i int; v_j int;
  v_behind boolean;
  -- 12 edges of a box: pairs of corner indices
  v_e1 int[] := ARRAY[1,2,4,3,5,6,8,7,1,2,3,4];
  v_e2 int[] := ARRAY[2,4,3,1,6,8,7,5,5,6,7,8];
  -- Depth for sorting
  v_depths float[];
  v_order int[];
  v_min_depth float; v_min_idx int;
  v_piece_ids int[];
  v_tmp int;
  v_tmpf float;
  -- Center label screen coords
  v_lcx float; v_lcy float;
  v_margin float := 20;
BEGIN
  IF array_length(p_mvp, 1) != 16 THEN
    RETURN '<svg xmlns="http://www.w3.org/2000/svg"><text fill="red" x="10" y="20">MVP matrix must have 16 elements</text></svg>';
  END IF;

  -- Collect piece IDs and their depths for back-to-front sorting
  v_piece_ids := p_piece_ids;
  v_depths := ARRAY[]::float[];
  FOR v_rec IN
    SELECT id,
      (ST_XMin(geom) + ST_XMax(geom)) / 2.0 AS mx,
      (ST_YMin(geom) + ST_YMax(geom)) / 2.0 AS my,
      (ST_ZMin(geom) + ST_ZMax(geom)) / 2.0 AS mz
    FROM cad.piece WHERE drawing_id = p_drawing_id AND id = ANY(p_piece_ids)
    ORDER BY id
  LOOP
    -- Convert center to Three.js: (mx, mz, -my)
    v_cx := v_rec.mx; v_cy := v_rec.mz; v_cz := -v_rec.my;
    -- Depth = distance to camera (z in clip space)
    v_clip_w := p_mvp[4]*v_cx + p_mvp[8]*v_cy + p_mvp[12]*v_cz + p_mvp[16];
    v_depths := v_depths || v_clip_w;
  END LOOP;

  -- Sort by depth descending (far first = painter's algorithm)
  v_order := ARRAY[]::int[];
  FOR v_i IN 1..array_length(v_piece_ids, 1) LOOP
    v_order := v_order || v_i;
  END LOOP;
  -- Bubble sort (small N)
  FOR v_i IN 1..array_length(v_order, 1)-1 LOOP
    FOR v_j IN v_i+1..array_length(v_order, 1) LOOP
      IF v_depths[v_order[v_i]] < v_depths[v_order[v_j]] THEN
        v_tmp := v_order[v_i]; v_order[v_i] := v_order[v_j]; v_order[v_j] := v_tmp;
      END IF;
    END LOOP;
  END LOOP;

  -- SVG header
  v_svg := format(
    '<svg xmlns="http://www.w3.org/2000/svg" width="%s" height="%s">'
    || '<rect width="100%%" height="100%%" fill="#1a1a2e"/>',
    p_width, p_height
  );

  -- Draw each piece as wireframe box
  FOR v_i IN 1..array_length(v_order, 1) LOOP
    SELECT INTO v_rec id, label, role, section, wood_type,
      ST_XMin(geom)::float AS xn, ST_YMin(geom)::float AS yn, ST_ZMin(geom)::float AS zn,
      ST_XMax(geom)::float AS xx, ST_YMax(geom)::float AS yx, ST_ZMax(geom)::float AS zx
    FROM cad.piece
    WHERE id = v_piece_ids[v_order[v_i]];

    IF NOT FOUND THEN CONTINUE; END IF;

    v_color := CASE v_rec.role
      WHEN 'poteau' THEN '#c8956c' WHEN 'traverse' THEN '#a07850'
      WHEN 'chevron' THEN '#d4a76a' WHEN 'lisse' THEN '#b8925a'
      ELSE '#c8a882'
    END;

    -- 8 corners: PostGIS (x,y,z) -> Three.js (x,z,-y)
    -- Corner 1: (xn, zn, -yn), 2: (xx, zn, -yn), 3: (xn, zn, -yx), 4: (xx, zn, -yx)
    -- Corner 5: (xn, zx, -yn), 6: (xx, zx, -yn), 7: (xn, zx, -yx), 8: (xx, zx, -yx)
    v_behind := false;
    FOR v_j IN 1..8 LOOP
      v_cx := CASE WHEN v_j IN (1,3,5,7) THEN v_rec.xn ELSE v_rec.xx END;
      v_cy := CASE WHEN v_j <= 4 THEN v_rec.zn ELSE v_rec.zx END;
      v_cz := CASE WHEN v_j IN (1,2,5,6) THEN -v_rec.yn ELSE -v_rec.yx END;

      -- MVP projection (column-major): clip = M * [x,y,z,1]
      v_clip_w := p_mvp[4]*v_cx + p_mvp[8]*v_cy + p_mvp[12]*v_cz + p_mvp[16];
      IF v_clip_w < 0.1 THEN v_behind := true; END IF;

      v_sx := (p_mvp[1]*v_cx + p_mvp[5]*v_cy + p_mvp[9]*v_cz + p_mvp[13]) / v_clip_w;
      v_sy := (p_mvp[2]*v_cx + p_mvp[6]*v_cy + p_mvp[10]*v_cz + p_mvp[14]) / v_clip_w;

      -- NDC -> screen
      v_screen[v_j][1] := (v_sx + 1.0) / 2.0 * p_width;
      v_screen[v_j][2] := (1.0 - v_sy) / 2.0 * p_height;
    END LOOP;

    IF v_behind THEN CONTINUE; END IF;

    -- Draw filled polygon (front face approximation using projected quad)
    v_svg := v_svg || format(
      '<polygon points="%s,%s %s,%s %s,%s %s,%s" fill="%s" fill-opacity="0.15" stroke="none"/>',
      round(v_screen[1][1]::numeric,1), round(v_screen[1][2]::numeric,1),
      round(v_screen[2][1]::numeric,1), round(v_screen[2][2]::numeric,1),
      round(v_screen[6][1]::numeric,1), round(v_screen[6][2]::numeric,1),
      round(v_screen[5][1]::numeric,1), round(v_screen[5][2]::numeric,1),
      v_color
    );

    -- Draw 12 edges
    FOR v_j IN 1..12 LOOP
      v_svg := v_svg || format(
        '<line x1="%s" y1="%s" x2="%s" y2="%s" stroke="%s" stroke-width="1.5" stroke-opacity="0.8"/>',
        round(v_screen[v_e1[v_j]][1]::numeric, 1), round(v_screen[v_e1[v_j]][2]::numeric, 1),
        round(v_screen[v_e2[v_j]][1]::numeric, 1), round(v_screen[v_e2[v_j]][2]::numeric, 1),
        v_color
      );
    END LOOP;

    -- Label at center of 8 corners
    v_lcx := 0; v_lcy := 0;
    FOR v_j IN 1..8 LOOP
      v_lcx := v_lcx + v_screen[v_j][1]; v_lcy := v_lcy + v_screen[v_j][2];
    END LOOP;
    v_lcx := v_lcx / 8.0; v_lcy := v_lcy / 8.0;

    v_label := cad._abbrev(v_rec.label, v_rec.role);
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#fff" font-family="monospace" font-size="12" font-weight="bold" '
      || 'text-anchor="middle" dominant-baseline="central" '
      || 'stroke="#000" stroke-width="3" paint-order="stroke">%s</text>',
      round(v_lcx::numeric, 1), round(v_lcy::numeric, 1), v_label
    );
  END LOOP;

  -- Legend
  v_sy := 20;
  FOR v_rec IN
    SELECT role, section,
      CASE role WHEN 'poteau' THEN '#c8956c' WHEN 'traverse' THEN '#a07850'
        WHEN 'chevron' THEN '#d4a76a' WHEN 'lisse' THEN '#b8925a' ELSE '#c8a882' END AS color,
      string_agg(cad._abbrev(label, role) || '=#' || id, '  ' ORDER BY label) AS items
    FROM cad.piece WHERE id = ANY(p_piece_ids)
    GROUP BY role, section ORDER BY role, section
  LOOP
    v_svg := v_svg || format(
      '<rect x="%s" y="%s" width="10" height="10" fill="%s" fill-opacity="0.6" stroke="%s"/>',
      v_margin, v_sy - 8, v_rec.color, v_rec.color
    );
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#aaa" font-family="monospace" font-size="9">%s %s: %s</text>',
      v_margin + 15, v_sy, v_rec.role, v_rec.section, v_rec.items
    );
    v_sy := v_sy + 16;
  END LOOP;

  v_svg := v_svg || '</svg>';
  RETURN v_svg;
END;
$function$;
COMMENT ON FUNCTION cad.render_perspective(integer,integer[],real[],integer,integer) IS 'Render 3D wireframe SVG using the camera MVP matrix from Three.js. Projects bounding box edges with perspective, painter algorithm depth sort, labels. Use with viewer Copier Vue button.';

CREATE OR REPLACE FUNCTION cad.render_shape_svg(p_shape cad.shape, p_layer_color text, p_unit text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_g jsonb := p_shape.geometry;
  v_el text := '';
BEGIN
  CASE p_shape.type
    WHEN 'line' THEN
      v_el := format('<line x1="%s" y1="%s" x2="%s" y2="%s"/>',
        v_g->>'x1', v_g->>'y1', v_g->>'x2', v_g->>'y2');
    WHEN 'rect' THEN
      v_el := format('<rect x="%s" y="%s" width="%s" height="%s"%s/>',
        v_g->>'x', v_g->>'y', v_g->>'w', v_g->>'h',
        CASE WHEN v_g->>'rotation' IS NOT NULL
          THEN format(' transform="rotate(%s %s %s)"',
            v_g->>'rotation',
            (v_g->>'x')::real + (v_g->>'w')::real/2,
            (v_g->>'y')::real + (v_g->>'h')::real/2)
          ELSE '' END);
    WHEN 'circle' THEN
      v_el := format('<circle cx="%s" cy="%s" r="%s"/>',
        v_g->>'cx', v_g->>'cy', v_g->>'r');
    WHEN 'arc' THEN
      v_el := cad.render_arc(v_g);
    WHEN 'polyline' THEN
      v_el := format('<polyline points="%s"/>',
        (SELECT string_agg(
          (p->0)::text || ',' || (p->1)::text, ' '
        ) FROM jsonb_array_elements(v_g->'points') AS p));
    WHEN 'text' THEN
      v_el := format('<text x="%s" y="%s" font-size="%s" text-anchor="%s" fill="%s" stroke="none">%s</text>',
        v_g->>'x', v_g->>'y',
        COALESCE(v_g->>'size', '14'),
        COALESCE(v_g->>'anchor', 'start'),
        p_layer_color,
        pgv.esc(v_g->>'content'));
    WHEN 'dimension' THEN
      v_el := cad.render_dimension(v_g, p_unit);
    ELSE
      RETURN '';
  END CASE;

  IF v_el IS NOT NULL AND v_el <> '' THEN
    RETURN format('<g data-shape-id="%s" class="shape"%s>%s</g>',
      p_shape.id,
      CASE WHEN p_shape.label IS NOT NULL
        THEN ' data-label="' || pgv.esc(p_shape.label) || '"'
        ELSE '' END,
      v_el);
  END IF;

  RETURN '';
END;
$function$;
COMMENT ON FUNCTION cad.render_shape_svg(cad.shape,text,text) IS 'Rend un shape individuel en SVG. Helper pour render_svg.';

CREATE OR REPLACE FUNCTION cad.render_group_svg(p_group_id integer, p_layer_color text, p_unit text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_shape cad.shape;
  v_svg text := '';
  v_label text;
BEGIN
  -- Label du groupe
  SELECT label INTO v_label FROM cad.shape WHERE id = p_group_id;

  FOR v_shape IN
    SELECT * FROM cad.shape WHERE parent_id = p_group_id ORDER BY sort_order
  LOOP
    IF v_shape.type = 'group' THEN
      v_svg := v_svg || cad.render_group_svg(v_shape.id, p_layer_color, p_unit);
    ELSE
      v_svg := v_svg || cad.render_shape_svg(v_shape, p_layer_color, p_unit);
    END IF;
  END LOOP;

  RETURN format('<g data-group-id="%s" class="group"%s>%s</g>',
    p_group_id,
    CASE WHEN v_label IS NOT NULL
      THEN ' data-label="' || pgv.esc(v_label) || '"'
      ELSE '' END,
    v_svg);
END;
$function$;
COMMENT ON FUNCTION cad.render_group_svg(integer,text,text) IS 'Rend un groupe et ses enfants récursivement en SVG.';

CREATE OR REPLACE FUNCTION cad.render_svg(p_drawing_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing cad.drawing;
  v_svg text := '';
  v_layer cad.layer;
  v_shape cad.shape;
  v_min_x real; v_min_y real; v_max_x real; v_max_y real;
  v_pad real := 50;
BEGIN
  SELECT * INTO v_drawing FROM cad.drawing WHERE id = p_drawing_id;
  IF NOT FOUND THEN RETURN ''; END IF;

  -- Marker pour les flèches de cotes
  v_svg := '<defs><marker id="arrow" viewBox="0 0 10 10" refX="5" refY="5"'
    || ' markerWidth="6" markerHeight="6" orient="auto-start-reverse">'
    || '<path d="M 0 0 L 10 5 L 0 10 z" fill="currentColor"/>'
    || '</marker></defs>';

  FOR v_layer IN
    SELECT * FROM cad.layer
    WHERE drawing_id = p_drawing_id AND visible
    ORDER BY sort_order
  LOOP
    v_svg := v_svg || format(
      '<g id="layer-%s" stroke="%s" stroke-width="%s" fill="none">',
      v_layer.id, v_layer.color, v_layer.stroke_width
    );

    -- Shapes racines (sans parent) de ce layer
    FOR v_shape IN
      SELECT * FROM cad.shape
      WHERE layer_id = v_layer.id AND parent_id IS NULL
      ORDER BY sort_order
    LOOP
      IF v_shape.type = 'group' THEN
        v_svg := v_svg || cad.render_group_svg(v_shape.id, v_layer.color, v_drawing.unit);
      ELSE
        v_svg := v_svg || cad.render_shape_svg(v_shape, v_layer.color, v_drawing.unit);
      END IF;
    END LOOP;

    v_svg := v_svg || '</g>';
  END LOOP;

  -- Bounding box dynamique (ignore les shapes de type group)
  SELECT
    min(LEAST(
      COALESCE((s.geometry->>'x')::real, (s.geometry->>'x1')::real, (s.geometry->>'cx')::real, 0),
      COALESCE((s.geometry->>'x2')::real, (s.geometry->>'x')::real, (s.geometry->>'cx')::real, 0)
    )),
    min(LEAST(
      COALESCE((s.geometry->>'y')::real, (s.geometry->>'y1')::real, (s.geometry->>'cy')::real, 0),
      COALESCE((s.geometry->>'y2')::real, (s.geometry->>'y')::real, (s.geometry->>'cy')::real, 0)
    )),
    max(GREATEST(
      COALESCE((s.geometry->>'x')::real + COALESCE((s.geometry->>'w')::real, 0), 0),
      COALESCE((s.geometry->>'x2')::real, 0),
      COALESCE((s.geometry->>'cx')::real + COALESCE((s.geometry->>'r')::real, 0), 0)
    )),
    max(GREATEST(
      COALESCE((s.geometry->>'y')::real + COALESCE((s.geometry->>'h')::real, 0), 0),
      COALESCE((s.geometry->>'y2')::real, 0),
      COALESCE((s.geometry->>'cy')::real + COALESCE((s.geometry->>'r')::real, 0), 0)
    ))
  INTO v_min_x, v_min_y, v_max_x, v_max_y
  FROM cad.shape s
  WHERE s.drawing_id = p_drawing_id AND s.type <> 'group';

  v_min_x := COALESCE(v_min_x, 0) - v_pad;
  v_min_y := COALESCE(v_min_y, 0) - v_pad;
  v_max_x := COALESCE(v_max_x, v_drawing.width) + v_pad;
  v_max_y := COALESCE(v_max_y, v_drawing.height) + v_pad;

  RETURN format(
    '<svg xmlns="http://www.w3.org/2000/svg" viewBox="%s %s %s %s" class="cad-canvas">%s</svg>',
    v_min_x, v_min_y, v_max_x - v_min_x, v_max_y - v_min_y, v_svg
  );
END;
$function$;
COMMENT ON FUNCTION cad.render_svg(integer) IS 'Génère le SVG complet d''un dessin avec support des groupes récursifs.';

CREATE OR REPLACE FUNCTION cad.page_drawing(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing cad.drawing;
  v_body text;
  v_shapes text;
  v_layers jsonb;
BEGIN
  SELECT * INTO v_drawing FROM cad.drawing WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.error('404', 'Dessin non trouvé', 'Le dessin #' || p_id || ' n''existe pas.');
  END IF;

  -- Canvas SVG interactif (pan + zoom)
  v_body := pgv.svg_canvas(cad.render_svg(p_id));

  -- Stats
  v_body := v_body || pgv.grid(
    pgv.stat('Shapes', (SELECT count(*)::text FROM cad.shape WHERE drawing_id = p_id)),
    pgv.stat('Calques', (SELECT count(*)::text FROM cad.layer WHERE drawing_id = p_id)),
    pgv.stat('Échelle', '1:' || v_drawing.scale::text),
    pgv.stat('Taille', v_drawing.width || ' × ' || v_drawing.height || ' ' || v_drawing.unit)
  );

  -- Liste des shapes
  SELECT string_agg(line, E'\n' ORDER BY sid) INTO v_shapes
  FROM (
    SELECT s.id AS sid,
      format('| %s | %s | %s | %s | %s |',
        s.id, s.type,
        COALESCE(s.label, '-'),
        l.name,
        pgv.action('shape_delete', 'Suppr.',
          jsonb_build_object('shape_id', s.id, 'drawing_id', p_id),
          'Supprimer cette shape ?', 'danger')
      ) AS line
    FROM cad.shape s
    JOIN cad.layer l ON l.id = s.layer_id
    WHERE s.drawing_id = p_id
  ) sub;

  IF v_shapes IS NOT NULL THEN
    v_body := v_body || '<md>' || E'\n'
      || '| ID | Type | Label | Calque | Action |' || E'\n'
      || '|----|------|-------|--------|--------|' || E'\n'
      || v_shapes || E'\n'
      || '</md>';
  END IF;

  -- Options calques en jsonb pour pgv.sel
  SELECT jsonb_agg(jsonb_build_object('value', l.id::text, 'label', l.name) ORDER BY l.sort_order)
  INTO v_layers
  FROM cad.layer l WHERE l.drawing_id = p_id;

  -- Formulaire ajout shape via RPC dédié
  v_body := v_body || '<details><summary>Ajouter une shape</summary>'
    || '<form data-rpc="shape_add">'
    || format('<input type="hidden" name="drawing_id" value="%s">', p_id)
    || '<div class="grid">'
    || pgv.sel('layer_id', 'Calque', COALESCE(v_layers, '[]'::jsonb))
    || pgv.sel('type', 'Type', '[
        {"value":"line","label":"Ligne"},
        {"value":"rect","label":"Rectangle"},
        {"value":"circle","label":"Cercle"},
        {"value":"text","label":"Texte"},
        {"value":"dimension","label":"Cote"}
      ]'::jsonb)
    || '</div>'
    || pgv.input('label', 'text', 'Label (optionnel)')
    || '<details><summary>Géométrie (JSON)</summary>'
    || pgv.textarea('geometry', 'Géométrie JSON', '{"x1":0,"y1":0,"x2":100,"y2":0}')
    || '</details>'
    || '<details><summary>Propriétés bois (JSON)</summary>'
    || pgv.textarea('props', 'Props JSON', '{}')
    || '</details>'
    || '<button type="submit">Ajouter</button>'
    || '</form></details>';

  -- Liens
  v_body := v_body || format(
    '<p><a href="/viewer.html?id=%s" target="_blank">Vue 3D</a> | <a href="/drawing/%s/bom">Liste de débit</a></p>', p_id, p_id);

  RETURN v_body;
END;
$function$;

CREATE OR REPLACE FUNCTION cad.page(p_path text, p_body jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parts text[];
  v_nav jsonb := '[{"href":"/","label":"Dessins"}]';
  v_brand text := 'CAD 3D';
  v_id int;
BEGIN
  v_parts := string_to_array(trim(BOTH '/' FROM p_path), '/');

  -- GET /
  IF p_path = '/' OR p_path IS NULL THEN
    RETURN pgv.page(v_brand, 'Dessins', '/', v_nav, cad.page_index());
  END IF;

  -- POST /drawing/add
  IF v_parts = ARRAY['drawing','add'] THEN
    RETURN cad.page_drawing_add(p_body);
  END IF;

  -- GET /drawing/:id
  IF array_length(v_parts,1) = 2 AND v_parts[1] = 'drawing' THEN
    v_id := v_parts[2]::int;
    RETURN pgv.page(v_brand, (SELECT name FROM cad.drawing WHERE id = v_id),
      p_path, v_nav, cad.page_drawing(v_id));
  END IF;

  -- GET /drawing/:id/3d
  IF array_length(v_parts,1) = 3 AND v_parts[1] = 'drawing' AND v_parts[3] = '3d' THEN
    v_id := v_parts[2]::int;
    RETURN pgv.page(v_brand, 'Vue 3D',
      p_path, v_nav, cad.page_drawing_3d(v_id));
  END IF;

  -- GET /drawing/:id/bom
  IF array_length(v_parts,1) = 3 AND v_parts[1] = 'drawing' AND v_parts[3] = 'bom' THEN
    v_id := v_parts[2]::int;
    RETURN pgv.page(v_brand, 'Liste de débit',
      p_path, v_nav, cad.page_drawing_bom(v_id));
  END IF;

  -- POST /drawing/:id/add-shape
  IF array_length(v_parts,1) = 3 AND v_parts[1] = 'drawing' AND v_parts[3] = 'add-shape' THEN
    v_id := v_parts[2]::int;
    RETURN cad.page_drawing_add_shape(v_id, p_body);
  END IF;

  -- POST /drawing/:id/delete-shape
  IF array_length(v_parts,1) = 3 AND v_parts[1] = 'drawing' AND v_parts[3] = 'delete-shape' THEN
    v_id := v_parts[2]::int;
    RETURN cad.page_drawing_delete_shape(v_id, p_body);
  END IF;

  -- 404
  RETURN pgv.page(v_brand, '404', p_path, v_nav,
    pgv.error('404', 'Page non trouvée', 'Le chemin ' || p_path || ' n''existe pas.'));
END;
$function$;

CREATE OR REPLACE FUNCTION cad.render_wireframe(p_drawing_id integer, p_axis text DEFAULT 'front'::text, p_width integer DEFAULT 900, p_height integer DEFAULT 700)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_svg text;
  v_xmin float; v_xmax float; v_ymin float; v_ymax float;
  v_sx float; v_sy float;
  v_x1 float; v_y1 float; v_x2 float; v_y2 float;
  v_color text;
  v_range_x float; v_range_y float;
  v_label text;
  v_margin float := 60;
  v_gx float; v_gy float;
  v_tick float;
  v_axis_labels text[];
BEGIN
  -- Bounds based on projection axis
  IF p_axis = 'front' THEN
    SELECT min(ST_XMin(geom)), max(ST_XMax(geom)), min(ST_ZMin(geom)), max(ST_ZMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
    v_axis_labels := ARRAY['X (mm)', 'Z (mm)', 'Front (XZ)'];
  ELSIF p_axis = 'top' THEN
    SELECT min(ST_XMin(geom)), max(ST_XMax(geom)), min(ST_YMin(geom)), max(ST_YMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
    v_axis_labels := ARRAY['X (mm)', 'Y (mm)', 'Top (XY)'];
  ELSE
    SELECT min(ST_YMin(geom)), max(ST_YMax(geom)), min(ST_ZMin(geom)), max(ST_ZMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
    v_axis_labels := ARRAY['Y (mm)', 'Z (mm)', 'Side (YZ)'];
  END IF;

  IF v_xmin IS NULL THEN
    RETURN '<svg xmlns="http://www.w3.org/2000/svg" width="200" height="40"><rect width="100%" height="100%" fill="#1a1a2e"/><text fill="#fff" x="10" y="25" font-family="monospace">empty model</text></svg>';
  END IF;

  -- 5% padding
  v_range_x := greatest(v_xmax - v_xmin, 1);
  v_range_y := greatest(v_ymax - v_ymin, 1);
  v_xmin := v_xmin - v_range_x * 0.05;
  v_xmax := v_xmax + v_range_x * 0.05;
  v_ymin := v_ymin - v_range_y * 0.05;
  v_ymax := v_ymax + v_range_y * 0.05;
  v_range_x := v_xmax - v_xmin;
  v_range_y := v_ymax - v_ymin;

  v_sx := (p_width - 2 * v_margin) / v_range_x;
  v_sy := (p_height - 2 * v_margin) / v_range_y;

  -- SVG header
  v_svg := format(
    '<svg xmlns="http://www.w3.org/2000/svg" width="%s" height="%s">'
    || '<rect width="100%%" height="100%%" fill="#1a1a2e"/>',
    p_width, p_height
  );

  -- Title
  v_svg := v_svg || format(
    '<text x="%s" y="25" fill="#8888cc" font-family="monospace" font-size="14" font-weight="bold">%s  %s x %s mm</text>',
    v_margin, v_axis_labels[3], round(v_range_x::numeric), round(v_range_y::numeric)
  );

  -- Grid + axis tick labels
  FOR v_rec IN SELECT generate_series(0, 5) AS i LOOP
    v_gx := v_margin + (p_width - 2 * v_margin) * v_rec.i / 5.0;
    v_svg := v_svg || format(
      '<line x1="%s" y1="%s" x2="%s" y2="%s" stroke="#2a2a44" stroke-width="0.5"/>',
      round(v_gx::numeric, 1), round(v_margin::numeric), round(v_gx::numeric, 1), round((p_height - v_margin)::numeric)
    );
    v_tick := v_xmin + v_range_x * v_rec.i / 5.0;
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#555" font-family="monospace" font-size="9" text-anchor="middle">%s</text>',
      round(v_gx::numeric, 1), p_height - v_margin + 14, round(v_tick::numeric)
    );

    v_gy := v_margin + (p_height - 2 * v_margin) * v_rec.i / 5.0;
    v_svg := v_svg || format(
      '<line x1="%s" y1="%s" x2="%s" y2="%s" stroke="#2a2a44" stroke-width="0.5"/>',
      round(v_margin::numeric), round(v_gy::numeric, 1), round((p_width - v_margin)::numeric), round(v_gy::numeric, 1)
    );
    v_tick := v_ymax - v_range_y * v_rec.i / 5.0;
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#555" font-family="monospace" font-size="9" text-anchor="end">%s</text>',
      v_margin - 5, round(v_gy::numeric, 1) + 3, round(v_tick::numeric)
    );
  END LOOP;

  -- Axis names
  v_svg := v_svg || format(
    '<text x="%s" y="%s" fill="#666" font-family="monospace" font-size="10" text-anchor="middle">%s</text>',
    round((p_width / 2)::numeric), p_height - v_margin + 30, v_axis_labels[1]
  );

  -- Ground line (z=0)
  IF p_axis IN ('front', 'side') AND v_ymin <= 0 AND v_ymax >= 0 THEN
    v_gy := v_margin + (p_height - 2 * v_margin) * (1.0 - (0 - v_ymin) / v_range_y);
    v_svg := v_svg || format(
      '<line x1="%s" y1="%s" x2="%s" y2="%s" stroke="#446644" stroke-width="1.5" stroke-dasharray="6,3"/>',
      round(v_margin::numeric), round(v_gy::numeric, 1), round((p_width - v_margin)::numeric), round(v_gy::numeric, 1)
    );
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#446644" font-family="monospace" font-size="9">sol</text>',
      p_width - v_margin + 4, round(v_gy::numeric, 1) + 3
    );
  END IF;

  -- Draw pieces (big first, small on top)
  FOR v_rec IN
    SELECT id, label, role, section,
      CASE p_axis WHEN 'front' THEN ST_XMin(geom) WHEN 'top' THEN ST_XMin(geom) ELSE ST_YMin(geom) END AS px1,
      CASE p_axis WHEN 'front' THEN ST_XMax(geom) WHEN 'top' THEN ST_XMax(geom) ELSE ST_YMax(geom) END AS px2,
      CASE p_axis WHEN 'front' THEN ST_ZMin(geom) WHEN 'top' THEN ST_YMin(geom) ELSE ST_ZMin(geom) END AS py1,
      CASE p_axis WHEN 'front' THEN ST_ZMax(geom) WHEN 'top' THEN ST_YMax(geom) ELSE ST_ZMax(geom) END AS py2
    FROM cad.piece WHERE drawing_id = p_drawing_id
    ORDER BY
      (CASE p_axis WHEN 'front' THEN (ST_XMax(geom)-ST_XMin(geom))*(ST_ZMax(geom)-ST_ZMin(geom))
                   WHEN 'top' THEN (ST_XMax(geom)-ST_XMin(geom))*(ST_YMax(geom)-ST_YMin(geom))
                   ELSE (ST_YMax(geom)-ST_YMin(geom))*(ST_ZMax(geom)-ST_ZMin(geom)) END) DESC
  LOOP
    v_color := CASE v_rec.role
      WHEN 'poteau' THEN '#c8956c'
      WHEN 'traverse' THEN '#a07850'
      WHEN 'chevron' THEN '#d4a76a'
      WHEN 'lisse' THEN '#b8925a'
      WHEN 'montant' THEN '#c8956c'
      ELSE '#c8a882'
    END;

    v_x1 := v_margin + (v_rec.px1 - v_xmin) * v_sx;
    v_x2 := v_margin + (v_rec.px2 - v_xmin) * v_sx;
    v_y1 := v_margin + (p_height - 2 * v_margin) * (1.0 - (v_rec.py2 - v_ymin) / v_range_y);
    v_y2 := v_margin + (p_height - 2 * v_margin) * (1.0 - (v_rec.py1 - v_ymin) / v_range_y);

    v_svg := v_svg || format(
      '<rect x="%s" y="%s" width="%s" height="%s" fill="%s" fill-opacity="0.5" stroke="%s" stroke-width="1.5" rx="1"/>',
      round(least(v_x1, v_x2)::numeric, 1), round(least(v_y1, v_y2)::numeric, 1),
      round(greatest(abs(v_x2 - v_x1), 1)::numeric, 1), round(greatest(abs(v_y2 - v_y1), 1)::numeric, 1),
      v_color, v_color
    );

    v_label := cad._abbrev(v_rec.label, v_rec.role);
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#fff" font-family="monospace" font-size="10" font-weight="bold" text-anchor="middle" dominant-baseline="central">%s</text>',
      round(((v_x1 + v_x2) / 2)::numeric, 1), round(((v_y1 + v_y2) / 2)::numeric, 1), v_label
    );
  END LOOP;

  -- Legend grouped by role+section
  v_gy := 20;
  FOR v_rec IN
    SELECT role, section,
      CASE role
        WHEN 'poteau' THEN '#c8956c' WHEN 'traverse' THEN '#a07850'
        WHEN 'chevron' THEN '#d4a76a' WHEN 'lisse' THEN '#b8925a'
        ELSE '#c8a882'
      END AS color,
      string_agg(cad._abbrev(label, role) || '=#' || id, '  ' ORDER BY label) AS items
    FROM cad.piece WHERE drawing_id = p_drawing_id
    GROUP BY role, section ORDER BY role, section
  LOOP
    v_svg := v_svg || format(
      '<rect x="%s" y="%s" width="10" height="10" fill="%s" fill-opacity="0.6" stroke="%s"/>',
      p_width - 260, v_margin + v_gy - 8, v_rec.color, v_rec.color
    );
    v_svg := v_svg || format(
      '<text x="%s" y="%s" fill="#aaa" font-family="monospace" font-size="9">%s %s: %s</text>',
      p_width - 245, v_margin + v_gy, v_rec.role, v_rec.section, v_rec.items
    );
    v_gy := v_gy + 16;
  END LOOP;

  v_svg := v_svg || '</svg>';
  RETURN v_svg;
END;
$function$;
COMMENT ON FUNCTION cad.render_wireframe(integer,text,integer,integer) IS 'Generate SVG wireframe projection of 3D model. Views: front (XZ), top (XY), side (YZ). Colored by role, labeled, with grid and coordinates. Convert to PNG with rsvg-convert for visual analysis.';

CREATE OR REPLACE FUNCTION cad.resize_piece(p_piece_id integer, p_new_length_mm double precision)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_p cad.piece;
  v_dx float; v_dy float; v_dz float;
  v_start real[]; v_end real[];
  v_old_length float;
BEGIN
  SELECT * INTO v_p FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_piece_id || ' not found'; END IF;

  v_old_length := v_p.length_mm;

  -- Determine the dominant axis by bounding box
  v_dx := ST_XMax(v_p.geom) - ST_XMin(v_p.geom);
  v_dy := ST_YMax(v_p.geom) - ST_YMin(v_p.geom);
  v_dz := ST_ZMax(v_p.geom) - ST_ZMin(v_p.geom);

  -- Rebuild start/end with new length, keeping origin
  IF v_dz > v_dx AND v_dz > v_dy THEN
    -- Vertical (Z dominant)
    v_start := ARRAY[ST_XMin(v_p.geom), ST_YMin(v_p.geom), ST_ZMin(v_p.geom)]::real[];
    v_end := ARRAY[ST_XMin(v_p.geom), ST_YMin(v_p.geom), ST_ZMin(v_p.geom) + p_new_length_mm]::real[];
  ELSIF v_dx > v_dy THEN
    -- Horizontal X dominant
    v_start := ARRAY[ST_XMin(v_p.geom), ST_YMin(v_p.geom), ST_ZMin(v_p.geom)]::real[];
    v_end := ARRAY[ST_XMin(v_p.geom) + p_new_length_mm, ST_YMin(v_p.geom), ST_ZMin(v_p.geom)]::real[];
  ELSE
    -- Horizontal Y dominant
    v_start := ARRAY[ST_XMin(v_p.geom), ST_YMin(v_p.geom), ST_ZMin(v_p.geom)]::real[];
    v_end := ARRAY[ST_XMin(v_p.geom), ST_YMin(v_p.geom) + p_new_length_mm, ST_ZMin(v_p.geom)]::real[];
  END IF;

  -- Create new piece via add_beam
  PERFORM cad.add_beam(
    v_p.drawing_id, v_p.section,
    v_start, v_end,
    v_p.label, v_p.role, v_p.wood_type
  );

  -- Remove old piece
  DELETE FROM cad.piece WHERE id = p_piece_id;

  RETURN 'resized: ' || coalesce(v_p.label, '#' || p_piece_id)
    || ' ' || v_old_length || 'mm -> ' || p_new_length_mm || 'mm'
    || E'\n' || cad.inspect(v_p.drawing_id);
END;
$function$;
COMMENT ON FUNCTION cad.resize_piece(integer,double precision) IS 'Redimensionner une piece (reconstruit via add_beam).';

CREATE OR REPLACE FUNCTION cad.scene_json(p_drawing_id integer)
 RETURNS jsonb
 LANGUAGE sql
AS $function$
  SELECT COALESCE(jsonb_agg(piece_data), '[]'::jsonb)
  FROM (
    SELECT jsonb_build_object(
      'id', p.id,
      'label', p.label,
      'role', p.role,
      'wood_type', p.wood_type,
      'section', p.section,
      'length_mm', p.length_mm,
      'mesh', (
        SELECT ST_AsGeoJSON(ST_Collect(tri.geom))::jsonb
        FROM ST_Dump(p.geom) AS face,
             LATERAL ST_Dump(ST_Tesselate(face.geom)) AS tri
      )
    ) AS piece_data
    FROM cad.piece p
    WHERE p.drawing_id = p_drawing_id
  ) sub;
$function$;
COMMENT ON FUNCTION cad.scene_json(integer) IS 'Export GeoJSON: tesselation des solides en triangles pour Three.js.';

CREATE OR REPLACE FUNCTION cad.shape_add(drawing_id integer, layer_id integer, type text, geometry text DEFAULT '{}'::text, props text DEFAULT '{}'::text, label text DEFAULT NULL::text)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_geometry jsonb;
  v_props jsonb;
  v_shape_id int;
BEGIN
  IF layer_id IS NULL OR type IS NULL THEN
    RETURN '<template data-toast="error">Calque et type requis</template>';
  END IF;

  BEGIN
    v_geometry := geometry::jsonb;
  EXCEPTION WHEN OTHERS THEN
    RETURN '<template data-toast="error">Géométrie JSON invalide</template>';
  END;

  BEGIN
    v_props := props::jsonb;
  EXCEPTION WHEN OTHERS THEN
    RETURN '<template data-toast="error">Props JSON invalides</template>';
  END;

  v_shape_id := cad.add_shape(drawing_id, layer_id, type, v_geometry, v_props, nullif(trim(COALESCE(label, '')), ''));

  RETURN format('<template data-toast="success">Shape #%s ajoutée</template>', v_shape_id)
    || format('<template data-redirect="/drawing/%s"></template>', drawing_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.shape_delete(shape_id integer, drawing_id integer)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF shape_id IS NULL THEN
    RETURN '<template data-toast="error">shape_id requis</template>';
  END IF;

  PERFORM cad.delete_shape(shape_id);

  RETURN format('<template data-toast="success">Shape #%s supprimée</template>', shape_id)
    || format('<template data-redirect="/drawing/%s"></template>', drawing_id);
END;
$function$;

CREATE OR REPLACE FUNCTION cad.snap_piece(p_piece_id integer, p_target_id integer, p_face text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src cad.piece;
  v_tgt cad.piece;
  v_dx float := 0; v_dy float := 0; v_dz float := 0;
BEGIN
  SELECT * INTO v_src FROM cad.piece WHERE id = p_piece_id;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_piece_id || ' not found'; END IF;
  SELECT * INTO v_tgt FROM cad.piece WHERE id = p_target_id;
  IF NOT FOUND THEN RETURN 'error: piece #' || p_target_id || ' not found'; END IF;

  -- Calculate translation to snap src against target's face
  CASE p_face
    WHEN 'top' THEN
      v_dz := ST_ZMax(v_tgt.geom) - ST_ZMin(v_src.geom);
    WHEN 'bottom' THEN
      v_dz := ST_ZMin(v_tgt.geom) - ST_ZMax(v_src.geom);
    WHEN 'right' THEN
      v_dx := ST_XMax(v_tgt.geom) - ST_XMin(v_src.geom);
    WHEN 'left' THEN
      v_dx := ST_XMin(v_tgt.geom) - ST_XMax(v_src.geom);
    WHEN 'back' THEN
      v_dy := ST_YMax(v_tgt.geom) - ST_YMin(v_src.geom);
    WHEN 'front' THEN
      v_dy := ST_YMin(v_tgt.geom) - ST_YMax(v_src.geom);
    ELSE
      RETURN 'error: invalid face "' || p_face || '". Use: top, bottom, left, right, front, back';
  END CASE;

  UPDATE cad.piece SET
    profile = ST_Translate(profile, v_dx, v_dy, v_dz),
    geom = ST_Translate(geom, v_dx, v_dy, v_dz)
  WHERE id = p_piece_id;

  RETURN 'snapped: ' || coalesce(v_src.label, '#' || p_piece_id)
    || ' -> ' || p_face || ' of ' || coalesce(v_tgt.label, '#' || p_target_id)
    || E'\nmoved: [' || round(v_dx::numeric,1) || ', ' || round(v_dy::numeric,1) || ', ' || round(v_dz::numeric,1) || ']'
    || E'\n' || cad.measure(p_piece_id, p_target_id);
END;
$function$;
COMMENT ON FUNCTION cad.snap_piece(integer,integer,text) IS 'Coller une piece contre une face d une autre piece.';

CREATE OR REPLACE FUNCTION cad.ungroup(p_group_id integer)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int;
BEGIN
  -- Vérifier que c'est bien un group
  IF NOT EXISTS (SELECT 1 FROM cad.shape WHERE id = p_group_id AND type = 'group') THEN
    RAISE EXCEPTION 'Shape % n''est pas un groupe', p_group_id;
  END IF;

  -- Détacher les enfants
  UPDATE cad.shape SET parent_id = NULL WHERE parent_id = p_group_id;
  GET DIAGNOSTICS v_count = ROW_COUNT;

  -- Supprimer le group
  DELETE FROM cad.shape WHERE id = p_group_id;

  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION cad.ungroup(integer) IS 'Dissocie un groupe : détache les enfants et supprime le shape group.';

CREATE OR REPLACE FUNCTION cad.view(p_drawing_id integer, p_axis text DEFAULT 'front'::text, p_width integer DEFAULT 80, p_height integer DEFAULT 40)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rec record;
  v_grid text[][];
  v_out text := '';
  v_xmin float; v_xmax float; v_ymin float; v_ymax float;
  v_sx float; v_sy float;  -- scale
  v_x1 int; v_y1 int; v_x2 int; v_y2 int;
  v_ch text;
  v_dx int; v_dy int; v_steps int; v_xi float; v_yi float;
  v_legend text := '';
  v_roles_seen text[] := '{}';
  v_is_thin boolean;
  v_step int;
  v_range_x float; v_range_y float;
BEGIN
  -- Init grid
  v_grid := array_fill(' '::text, ARRAY[p_height, p_width]);

  -- Bounds
  IF p_axis = 'front' THEN
    SELECT min(ST_XMin(geom)), max(ST_XMax(geom)), min(ST_ZMin(geom)), max(ST_ZMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
  ELSIF p_axis = 'top' THEN
    SELECT min(ST_XMin(geom)), max(ST_XMax(geom)), min(ST_YMin(geom)), max(ST_YMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
  ELSE
    SELECT min(ST_YMin(geom)), max(ST_YMax(geom)), min(ST_ZMin(geom)), max(ST_ZMax(geom))
    INTO v_xmin, v_xmax, v_ymin, v_ymax FROM cad.piece WHERE drawing_id = p_drawing_id;
  END IF;

  IF v_xmin IS NULL THEN RETURN 'empty model'; END IF;

  -- 5% margin
  v_range_x := greatest(v_xmax - v_xmin, 1);
  v_range_y := greatest(v_ymax - v_ymin, 1);
  v_xmin := v_xmin - v_range_x * 0.05;
  v_xmax := v_xmax + v_range_x * 0.05;
  v_ymin := v_ymin - v_range_y * 0.05;
  v_ymax := v_ymax + v_range_y * 0.05;
  v_range_x := v_xmax - v_xmin;
  v_range_y := v_ymax - v_ymin;

  v_sx := (p_width - 1) / v_range_x;
  v_sy := (p_height - 1) / v_range_y;

  -- Draw ground line at z=0 (for front/side views)
  IF p_axis IN ('front', 'side') AND v_ymin <= 0 AND v_ymax >= 0 THEN
    v_y1 := (p_height - 1) - round((0 - v_ymin) * v_sy)::int;
    IF v_y1 >= 0 AND v_y1 < p_height THEN
      FOR v_step IN 1..p_width LOOP
        IF v_grid[v_y1 + 1][v_step] = ' ' THEN
          v_grid[v_y1 + 1][v_step] := '.';
        END IF;
      END LOOP;
    END IF;
  END IF;

  -- Draw pieces: role-based characters
  -- Thick pieces = filled rect, thin pieces = line trace (Bresenham)
  FOR v_rec IN
    SELECT id, label, role, section,
      CASE p_axis WHEN 'front' THEN ST_XMin(geom) WHEN 'top' THEN ST_XMin(geom) ELSE ST_YMin(geom) END AS px1,
      CASE p_axis WHEN 'front' THEN ST_XMax(geom) WHEN 'top' THEN ST_XMax(geom) ELSE ST_YMax(geom) END AS px2,
      CASE p_axis WHEN 'front' THEN ST_ZMin(geom) WHEN 'top' THEN ST_YMin(geom) ELSE ST_ZMin(geom) END AS py1,
      CASE p_axis WHEN 'front' THEN ST_ZMax(geom) WHEN 'top' THEN ST_YMax(geom) ELSE ST_ZMax(geom) END AS py2,
      -- Centerline start/end for diagonal tracing
      CASE p_axis WHEN 'front' THEN (ST_XMin(geom)+ST_XMax(geom))/2 WHEN 'top' THEN (ST_XMin(geom)+ST_XMax(geom))/2 ELSE (ST_YMin(geom)+ST_YMax(geom))/2 END AS cx1,
      CASE p_axis WHEN 'front' THEN (ST_XMin(geom)+ST_XMax(geom))/2 WHEN 'top' THEN (ST_XMin(geom)+ST_XMax(geom))/2 ELSE (ST_YMin(geom)+ST_YMax(geom))/2 END AS cx2,
      CASE p_axis WHEN 'front' THEN ST_ZMin(geom) WHEN 'top' THEN ST_YMin(geom) ELSE ST_ZMin(geom) END AS cy1,
      CASE p_axis WHEN 'front' THEN ST_ZMax(geom) WHEN 'top' THEN ST_YMax(geom) ELSE ST_ZMax(geom) END AS cy2
    FROM cad.piece WHERE drawing_id = p_drawing_id
    ORDER BY
      -- Draw big pieces first so small ones appear on top
      (CASE p_axis WHEN 'front' THEN (ST_XMax(geom)-ST_XMin(geom))*(ST_ZMax(geom)-ST_ZMin(geom))
                   WHEN 'top' THEN (ST_XMax(geom)-ST_XMin(geom))*(ST_YMax(geom)-ST_YMin(geom))
                   ELSE (ST_YMax(geom)-ST_YMin(geom))*(ST_ZMax(geom)-ST_ZMin(geom)) END) DESC
  LOOP
    -- Role-based character
    v_ch := CASE v_rec.role
      WHEN 'poteau' THEN '|'
      WHEN 'lisse' THEN '-'
      WHEN 'traverse' THEN '='
      WHEN 'chevron' THEN '/'
      WHEN 'montant' THEN '|'
      ELSE '#'
    END;

    -- Screen coords of bbox
    v_x1 := round((v_rec.px1 - v_xmin) * v_sx)::int;
    v_x2 := round((v_rec.px2 - v_xmin) * v_sx)::int;
    v_y1 := (p_height-1) - round((v_rec.py2 - v_ymin) * v_sy)::int;
    v_y2 := (p_height-1) - round((v_rec.py1 - v_ymin) * v_sy)::int;

    -- Is this piece "thin" in projection? (diagonal beam seen from side)
    v_is_thin := (abs(v_x2 - v_x1) > 3 AND abs(v_y2 - v_y1) > 3);

    IF v_is_thin THEN
      -- Trace diagonal line (Bresenham-ish) through center
      v_dx := abs(v_x2 - v_x1);
      v_dy := abs(v_y2 - v_y1);
      v_steps := greatest(v_dx, v_dy);
      FOR v_step IN 0..v_steps LOOP
        v_xi := v_x1 + (v_x2 - v_x1) * v_step::float / greatest(v_steps, 1);
        v_yi := v_y1 + (v_y2 - v_y1) * v_step::float / greatest(v_steps, 1);
        -- Draw with 1px thickness
        IF round(v_xi)::int BETWEEN 0 AND p_width-1
           AND round(v_yi)::int BETWEEN 0 AND p_height-1 THEN
          v_grid[round(v_yi)::int + 1][round(v_xi)::int + 1] := v_ch;
        END IF;
      END LOOP;
    ELSE
      -- Fill rectangle
      v_x1 := greatest(0, least(v_x1, p_width-1));
      v_x2 := greatest(0, least(v_x2, p_width-1));
      v_y1 := greatest(0, least(v_y1, p_height-1));
      v_y2 := greatest(0, least(v_y2, p_height-1));
      FOR v_step IN v_y1..v_y2 LOOP
        FOR v_dx IN v_x1..v_x2 LOOP
          v_grid[v_step + 1][v_dx + 1] := v_ch;
        END LOOP;
      END LOOP;
    END IF;

    -- Legend: only first occurrence per role
    IF NOT v_rec.role = ANY(v_roles_seen) THEN
      v_roles_seen := v_roles_seen || v_rec.role;
      v_legend := v_legend || '  ' || v_ch || ' = ' || v_rec.role || E'\n';
    END IF;
  END LOOP;

  -- Header with scale
  v_out := CASE p_axis
    WHEN 'front' THEN format('Front (XZ)  %s x %s mm', round(v_range_x::numeric), round(v_range_y::numeric))
    WHEN 'top' THEN format('Top (XY)  %s x %s mm', round(v_range_x::numeric), round(v_range_y::numeric))
    ELSE format('Side (YZ)  %s x %s mm', round(v_range_x::numeric), round(v_range_y::numeric))
  END || E'\n';

  -- Render grid
  FOR v_step IN 1..p_height LOOP
    FOR v_dx IN 1..p_width LOOP
      v_out := v_out || v_grid[v_step][v_dx];
    END LOOP;
    v_out := v_out || E'\n';
  END LOOP;

  v_out := v_out || v_legend;
  RETURN v_out;
END;
$function$;
COMMENT ON FUNCTION cad.view(integer,text,integer,integer) IS 'Rendu ASCII du modele. Projections: front (XZ), top (XY), side (YZ). Diagonales tracees, caracteres par role, ligne de sol.';

GRANT USAGE ON SCHEMA cad TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA cad TO web_anon;

-- Schema: cad_ut
CREATE SCHEMA IF NOT EXISTS cad_ut;

CREATE OR REPLACE FUNCTION cad_ut.test_add_shape()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_sid int;
BEGIN
  INSERT INTO cad.drawing (name) VALUES ('test_add') RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name) VALUES (v_did, 'L1') RETURNING id INTO v_lid;

  v_sid := cad.add_shape(v_did, v_lid, 'line', '{"x1":0,"y1":0,"x2":100,"y2":0}');
  RETURN NEXT ok(v_sid IS NOT NULL, 'add_shape returns an id');
  RETURN NEXT is(
    (SELECT type FROM cad.shape WHERE id = v_sid), 'line', 'shape type is line'
  );
  RETURN NEXT is(
    (SELECT geometry->>'x2' FROM cad.shape WHERE id = v_sid), '100', 'geometry x2 = 100'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_delete_shape()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_sid int;
BEGIN
  INSERT INTO cad.drawing (name) VALUES ('test_del') RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name) VALUES (v_did, 'L1') RETURNING id INTO v_lid;

  v_sid := cad.add_shape(v_did, v_lid, 'rect', '{"x":0,"y":0,"w":50,"h":30}');
  PERFORM cad.delete_shape(v_sid);

  RETURN NEXT ok(
    NOT EXISTS(SELECT 1 FROM cad.shape WHERE id = v_sid),
    'shape deleted'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_move_shape()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_sid int;
  v_g jsonb;
BEGIN
  INSERT INTO cad.drawing (name) VALUES ('test_move') RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name) VALUES (v_did, 'L1') RETURNING id INTO v_lid;

  v_sid := cad.add_shape(v_did, v_lid, 'line', '{"x1":0,"y1":0,"x2":100,"y2":0}');
  PERFORM cad.move_shape(v_sid, 10, 20);

  SELECT geometry INTO v_g FROM cad.shape WHERE id = v_sid;
  RETURN NEXT is((v_g->>'x1')::real, 10::real, 'x1 moved +10');
  RETURN NEXT is((v_g->>'y1')::real, 20::real, 'y1 moved +20');
  RETURN NEXT is((v_g->>'x2')::real, 110::real, 'x2 moved +10');
END;
$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_render_svg()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_did int;
  v_lid int;
  v_svg text;
BEGIN
  INSERT INTO cad.drawing (name, width, height) VALUES ('test_svg', 500, 400) RETURNING id INTO v_did;
  INSERT INTO cad.layer (drawing_id, name, color) VALUES (v_did, 'L1', '#ff0000') RETURNING id INTO v_lid;

  PERFORM cad.add_shape(v_did, v_lid, 'line', '{"x1":0,"y1":0,"x2":100,"y2":100}');
  PERFORM cad.add_shape(v_did, v_lid, 'rect', '{"x":200,"y":50,"w":80,"h":60}');
  PERFORM cad.add_shape(v_did, v_lid, 'circle', '{"cx":300,"cy":200,"r":40}');

  v_svg := cad.render_svg(v_did);

  RETURN NEXT ok(v_svg LIKE '%<svg%', 'svg tag present');
  RETURN NEXT ok(v_svg LIKE '%viewBox="%', 'viewBox present');
  RETURN NEXT ok(v_svg LIKE '%<line%', 'contains line element');
  RETURN NEXT ok(v_svg LIKE '%<rect%', 'contains rect element');
  RETURN NEXT ok(v_svg LIKE '%<circle%', 'contains circle element');
  RETURN NEXT ok(v_svg LIKE '%stroke="#ff0000"%', 'layer color applied');
END;
$function$;

CREATE OR REPLACE FUNCTION cad_ut.test_group_shapes()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_drawing_id int;
  v_layer_id int;
  v_s1 int; v_s2 int; v_s3 int;
  v_group_id int;
  v_svg text;
  v_count int;
BEGIN
  -- Setup
  INSERT INTO cad.drawing (name) VALUES ('test_group') RETURNING id INTO v_drawing_id;
  INSERT INTO cad.layer (drawing_id, name) VALUES (v_drawing_id, 'default') RETURNING id INTO v_layer_id;
  
  v_s1 := cad.add_shape(v_drawing_id, v_layer_id, 'line', '{"x1":0,"y1":0,"x2":100,"y2":0}');
  v_s2 := cad.add_shape(v_drawing_id, v_layer_id, 'line', '{"x1":100,"y1":0,"x2":100,"y2":100}');
  v_s3 := cad.add_shape(v_drawing_id, v_layer_id, 'rect', '{"x":200,"y":200,"w":50,"h":50}');

  -- Test group_shapes
  v_group_id := cad.group_shapes(v_drawing_id, ARRAY[v_s1, v_s2], 'Mur nord');
  RETURN NEXT ok(v_group_id IS NOT NULL, 'group created');
  RETURN NEXT ok(
    (SELECT type FROM cad.shape WHERE id = v_group_id) = 'group',
    'group type is group'
  );
  RETURN NEXT ok(
    (SELECT count(*) FROM cad.shape WHERE parent_id = v_group_id) = 2,
    'group has 2 children'
  );
  RETURN NEXT ok(
    (SELECT parent_id FROM cad.shape WHERE id = v_s3) IS NULL,
    's3 not in group'
  );

  -- Test SVG rendering with group
  v_svg := cad.render_svg(v_drawing_id);
  RETURN NEXT ok(v_svg LIKE '%data-group-id="' || v_group_id || '"%', 'svg contains group element');
  RETURN NEXT ok(v_svg LIKE '%data-label="Mur nord"%', 'group label rendered');

  -- Test move_group
  v_count := cad.move_group(v_group_id, 10, 20);
  RETURN NEXT is(v_count, 2, 'move_group moved 2 shapes');
  RETURN NEXT is(
    (SELECT (geometry->>'x1')::real FROM cad.shape WHERE id = v_s1),
    10::real, 'shape x1 moved +10'
  );

  -- Test ungroup
  v_count := cad.ungroup(v_group_id);
  RETURN NEXT is(v_count, 2, 'ungroup detached 2 shapes');
  RETURN NEXT ok(
    NOT EXISTS (SELECT 1 FROM cad.shape WHERE id = v_group_id),
    'group shape deleted'
  );
  RETURN NEXT ok(
    (SELECT parent_id FROM cad.shape WHERE id = v_s1) IS NULL,
    's1 detached after ungroup'
  );

  -- Cleanup
  DELETE FROM cad.drawing WHERE id = v_drawing_id;
END;
$function$;

GRANT USAGE ON SCHEMA cad_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA cad_ut TO web_anon;
